// AUTO-GENERATED from the SacredOps OSHA toolbox-talk library (48 talks).
// Each talk carries its full content; the Supervisor Portal prints these
// sections above the signed sign-in sheet when a talk is delivered.
export type ToolboxTalk = { id: string; title: string; ref: string; sections: { h: string; body: string[] }[] };
export const TOOLBOX_TALKS: ToolboxTalk[] = [{"id": "01","title": "Fall Protection — General Requirements","ref": "OSHA Focus Four   |   OSHA 29 CFR 1926.501","sections": [{"h": "SUMMARY","body": ["Falls remain construction’s leading fatal hazard. This talk reinforces the 6-foot construction trigger, proper guardrails or PFAS use, daily inspection, tie-off discipline, and rescue planning before anyone works at height."]},{"h": "IMPORTANT FACTS","body": ["Falls are the #1 cause of construction death. In 2024, 370 construction workers died from falls. OSHA also cited fall protection nearly 5,900 times in FY2025, making it the most-cited standard for the 14th straight year."]},{"h": "WHY IT MATTERS","body": ["Falls are the leading killer in construction and 1926.501 has been OSHA's single most-cited standard for 14 consecutive years. In 2024, 370 construction workers died from falls — down 7.5% from 2023, but still roughly four out of every ten construction deaths. OSHA and NIOSH agree the overwhelming majority of fall fatalities were preventable with equipment the employer was already required to provide."]},{"h": "KEY HAZARDS","body": ["Unprotected leading edges, roofs, and floor openings 6 ft or more above a lower level","Skylights and fragile surfaces that will not hold a worker's weight","Improperly rigged or missing guardrails, safety nets, and personal fall arrest systems (PFAS)","Falls into excavations, wells, pits, and shafts","Reroofing, decking, and edge work where the fall distance is greatest"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Fall protection is required at 6 ft or more above a lower level in construction (general industry trigger is 4 ft).","PFAS anchor points must support 5,000 lb per worker, or be designed to a 2:1 safety factor by a qualified person.","Guardrail top rails: 42 in ±3 in high, able to withstand 200 lb of outward/downward force; mid-rails withstand 150 lb.","A PFAS must limit maximum arresting force to 1,800 lb, free fall to 6 ft or less, and stop the worker within 3.5 ft of deceleration."]},{"h": "SAFE WORK PRACTICES","body": ["Use guardrails, safety nets, or a PFAS any time you are exposed to a 6-ft-or-greater fall — no exceptions without an approved plan.","Inspect the full harness, lanyard, and connectors before every use; remove any component from service after it arrests a fall.","Tie off to an approved, overhead anchor — never to guardrails, rebar caps, conduit, or a coworker.","Connect the lanyard to the dorsal (back) D-ring and account for total fall clearance and swing-fall below you.","Cover and secure every floor hole and opening; mark covers \"HOLE\" or \"COVER\" and secure against displacement.","Maintain 100% tie-off when moving at height by using a twin-leg (Y) lanyard.","Have a prompt rescue plan — suspension trauma can become life-threatening within minutes of a fall."]},{"h": "PPE NEEDED","body": ["Full-body harness with shock-absorbing lanyard or self-retracting lifeline when guardrails or nets are not used","Approved anchor/connectors rated for the task","Hard hat, safety glasses, high-visibility vest, and safety-toe boots","Task-specific gloves and rescue equipment available before work starts"]}]},{"id": "02","title": "Struck-By Hazards","ref": "OSHA Focus Four   |   OSHA 29 CFR 1926 Subpart O / General Duty","sections": [{"h": "SUMMARY","body": ["Struck-by hazards come from moving equipment, falling objects, flying particles, and suspended loads. This talk focuses the crew on line-of-fire awareness, exclusion zones, eye contact, overhead protection, and high-visibility practices."]},{"h": "IMPORTANT FACTS","body": ["Struck-by incidents are the second-leading cause of construction deaths and account for roughly 11% of construction fatalities. More than 150 workers are killed by struck-by objects each year."]},{"h": "WHY IT MATTERS","body": ["Struck-by incidents are the second-leading cause of construction deaths, behind only falls, and the single biggest source of nonfatal construction injuries. Flying, falling, swinging, and rolling objects — plus vehicles and mobile equipment — put workers in the line of fire every day. A dropped hand tool from just a few stories can strike with enough force to kill."]},{"h": "KEY HAZARDS","body": ["Vehicles and mobile equipment operating in and around the work area","Tools, materials, and loads falling from overhead work, scaffolds, and lifts","Flying particles from grinding, cutting, nailing, chipping, and demolition","Swinging or suspended crane loads and load release","Nail-gun and powder-actuated tool discharge; compressed-air projectiles"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Toe boards (min 3.5 in high) or screens are required where people work or pass below, and where tools/materials could fall.","Hard hats meeting ANSI Z89.1 are required wherever there is a risk of head injury from impact or falling objects.","Barricade the swing radius of rotating superstructures (e.g., excavators, cranes) to keep workers out.","Eye and face protection meeting ANSI Z87.1 is required for operations producing flying particles."]},{"h": "SAFE WORK PRACTICES","body": ["Stay out of the swing radius of cranes and excavators and never stand under a suspended load.","Wear high-visibility apparel and make eye contact with operators before entering their path.","Secure tools and materials at heights; use tool lanyards, toe boards, and debris netting.","Never bypass or remove machine and tool guards; wear eye/face protection for grinding and cutting.","Stack and store materials so they cannot slide, roll, or topple.","Keep clear of backing vehicles; require spotters, backup alarms, and eye contact in blind zones.","Position yourself so you can never be pinned between equipment and a fixed object."]},{"h": "PPE NEEDED","body": ["ANSI-rated hard hat for falling-object and impact exposure","Safety glasses with side shields; face shield for grinding, cutting, or chipping","High-visibility vest or shirt when working around vehicles or mobile equipment","Safety-toe boots and task-appropriate gloves"]}]},{"id": "03","title": "Caught-In or -Between Hazards","ref": "OSHA Focus Four   |   OSHA 29 CFR 1926 Subparts O & P","sections": [{"h": "SUMMARY","body": ["Caught-in and caught-between events are fast, heavy, and often fatal. This talk highlights trench protection, machine guarding, lockout, pinch-point awareness, and keeping workers out from between equipment and fixed objects."]},{"h": "IMPORTANT FACTS","body": ["Caught-in or caught-between hazards cause about 5% of construction deaths. One cubic yard of soil can weigh around 3,000 pounds, and a cave-in can bury a worker in seconds."]},{"h": "WHY IT MATTERS","body": ["Caught-in/-between hazards — trench cave-ins, unguarded machinery, and being pinned or crushed — cause about 5% of construction deaths. The danger is speed and weight: a single cubic yard of soil weighs roughly 3,000 pounds, and a trench wall collapses faster than a worker can react. More than 250 workers have died in trench collapses since 2013 alone."]},{"h": "KEY HAZARDS","body": ["Unprotected trenches and excavations 5 ft deep or greater","Unguarded rotating parts, augers, gears, and in-running nip points","Being caught between equipment and walls, materials, or structures","Collapsing walls, unsupported structures, and shifting materials","Clothing, gloves, or jewelry drawn into moving machinery"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["A protective system (sloping, benching, shoring, or a trench box) is required in excavations 5 ft deep or greater — and shallower if a competent person finds a cave-in hazard.","Spoil piles, equipment, and materials must be kept at least 2 ft back from the trench edge.","Machine guards are required on points of operation, nip points, and rotating parts.","Energy must be locked out before removing a guard or clearing a jam (see LOTO)."]},{"h": "SAFE WORK PRACTICES","body": ["Never enter a trench 5 ft or deeper without an approved protective system in place.","Keep hands, tools, and loose clothing away from rotating parts and pinch points.","Verify guards are in place before operating; lock out energy before clearing jams or servicing.","Never position yourself between moving equipment and an immovable object.","Have a competent person inspect excavations daily and after rain, vibration, or any change.","Keep a means of egress (ladder/ramp) within 25 ft in trenches 4 ft or deeper."]},{"h": "PPE NEEDED","body": ["Hard hat, safety glasses, high-visibility apparel, and safety-toe boots","Cut-resistant or impact gloves when handling materials, tools, or rebar","No loose gloves, jewelry, or clothing near rotating machinery","Fall protection or trench-specific protection where required by the task"]}]},{"id": "04","title": "Electrocution & Electrical Safety","ref": "OSHA Focus Four   |   OSHA 29 CFR 1926 Subpart K","sections": [{"h": "SUMMARY","body": ["Electrical hazards kill through contact, shock, burns, and secondary falls. This talk emphasizes treating conductors as energized, using GFCI protection, maintaining power-line clearance, inspecting cords/tools, and keeping unqualified workers away from energized parts."]},{"h": "IMPORTANT FACTS","body": ["Electrocution causes roughly 8% of construction deaths. Overhead power lines are involved in nearly half of workplace electrical fatalities, and construction leads all industries in electrical deaths."]},{"h": "WHY IT MATTERS","body": ["Electrocution causes roughly 8% of construction deaths, and construction has the highest number of electrical fatalities of any industry. Contact with overhead power lines is the leading cause — behind nearly half of all workplace electrical deaths. Even non-fatal shocks cause severe burns, cardiac effects, and secondary falls."]},{"h": "KEY HAZARDS","body": ["Overhead and underground power lines","Damaged extension cords, tools, and missing ground pins","Wet or damp conditions combined with electrical equipment","Working on or near energized circuits without lockout","Improper grounding and reversed polarity"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Maintain at least 10 ft of clearance from overhead lines up to 50 kV; add 4 in per 10 kV above that.","GFCI protection is required on all 120V, single-phase, 15/20/30-amp receptacles used on construction sites (or an assured equipment grounding conductor program).","Only qualified persons may work on or near exposed energized parts.","Call 811 to locate underground utilities before any digging."]},{"h": "SAFE WORK PRACTICES","body": ["Treat every wire as energized until it is verified de-energized and locked out.","Maintain the required clearance from overhead lines when using cranes, ladders, lifts, and long tools.","Use GFCI protection on all site power and test the GFCIs regularly.","Inspect cords and tools before use; remove any with cracked insulation or missing ground pins.","Keep electrical equipment, cords, and connections out of standing water and wet areas.","Never bypass grounding; use only three-prong or double-insulated tools.","Keep unqualified workers clear of energized equipment and panels."]},{"h": "PPE NEEDED","body": ["Electrical-rated gloves and arc-rated PPE only when required and assigned to qualified electrical work","Hard hat, safety glasses, and safety-toe boots; use non-conductive ladders near electrical hazards","Rubber insulating gloves, sleeves, mats, or tools when specified by the electrical work plan","No metal jewelry or conductive items when working near energized parts"]}]},{"id": "05","title": "Ladder Safety","ref": "Falls, Heights & Access   |   OSHA 29 CFR 1926.1053","sections": [{"h": "SUMMARY","body": ["Ladder injuries are common because ladders feel routine. This talk reinforces inspection, correct setup angle, secure access, three points of contact, hands-free climbing, and choosing non-conductive ladders near electrical hazards."]},{"h": "IMPORTANT FACTS","body": ["Ladder safety is one of OSHA’s most-cited construction standards. Ladder falls cause hundreds of deaths and thousands of emergency-room visits each year, and many fatal falls happen from 10 feet or less."]},{"h": "WHY IT MATTERS","body": ["Ladders are OSHA's third most-cited construction standard and the leading equipment in construction fall injuries — 81% of construction fall injuries treated in ERs involve a ladder. Nationwide, ladder falls cause about 300 deaths and 164,000 emergency-room visits a year. Most fatal ladder falls are from 10 feet or less, and nearly half involve a head injury."]},{"h": "KEY HAZARDS","body": ["Ladders set on uneven, soft, or slippery surfaces","Overreaching, over-loading, or carrying loads while climbing","Damaged rails, rungs, or slip-resistant feet","Metal ladders used near electrical hazards","Wrong ladder type or height for the task"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Set extension ladders at a 4:1 pitch — 1 ft of base for every 4 ft of working height.","Side rails must extend at least 3 ft above the upper landing surface, and the ladder must be secured.","Ladders must support at least 4x the maximum intended load (extra-heavy-duty types more).","Only one person on a ladder at a time (unless designed for more); keep the area around the base clear."]},{"h": "SAFE WORK PRACTICES","body": ["Inspect the ladder before use; tag and remove damaged ladders from service.","Maintain 3 points of contact and always face the ladder when climbing.","Keep your belt buckle between the side rails — never overreach; get down and move the ladder.","Extend and secure the top, and tie off or have someone hold the base on slick surfaces.","Use a fiberglass (non-conductive) ladder near any electrical work — never aluminum.","Do not stand on the top two rungs of a stepladder; use the correct height for the job.","Hoist tools/materials separately — keep hands free for climbing."]},{"h": "PPE NEEDED","body": ["Hard hat, safety glasses, and slip-resistant safety-toe boots","Tool belt or hoisting line so hands stay free while climbing","Electrical-rated or fiberglass ladder selection near energized sources","Fall protection when transitioning to exposed work at height, if required by the task"]}]},{"id": "06","title": "Stairways & Site Access","ref": "Falls, Heights & Access   |   OSHA 29 CFR 1926.1052 / 1926.1051","sections": [{"h": "SUMMARY","body": ["Stairways and access routes are used by everyone and can quickly become slip, trip, and evacuation hazards. This talk reinforces clean access, proper handrails, filled pan stairs, lighting, and immediate correction of mud, debris, and uneven walking surfaces."]},{"h": "IMPORTANT FACTS","body": ["Same-level falls are among the most common recordable injuries. Debris, uneven walking surfaces, and unprotected changes in elevation are frequent causes of stairway and access-route incidents."]},{"h": "WHY IT MATTERS","body": ["Temporary stairs and access routes are high-traffic and often the most neglected part of the site. Missing handrails, debris on treads, and unfinished pan stairs cause slips and falls that are simple and inexpensive to prevent. Good access is also how crews evacuate quickly in an emergency."]},{"h": "KEY HAZARDS","body": ["Stairways without handrails at 4+ risers or a 30 in rise","Debris, mud, tools, cords, and materials on treads and landings","Unequal riser heights and unfilled metal pans","Poor lighting and unmarked changes in elevation"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["A stairrail is required on stairways with 4 or more risers or rising more than 30 in; handrails must withstand 200 lb.","A stairway, ramp, or ladder is required at any point of access with a break in elevation of 19 in or more.","Metal pan stairs must be filled with concrete or approved material before use.","Riser height and tread depth must be uniform within each flight (±¼ in)."]},{"h": "SAFE WORK PRACTICES","body": ["Keep stairs, landings, and walkways clear of tools, cords, and debris at all times.","Fill metal-pan stairs before use — never \"skeleton-walk\" open pans.","Provide and maintain proper stairrails and handrails; report loose or wobbling rails.","Light all access routes adequately and mark elevation changes.","Use the designated path of travel — don't take shortcuts across the structure.","Clean up spills and mud on treads immediately."]},{"h": "PPE NEEDED","body": ["Slip-resistant safety-toe footwear suited to mud, water, ice, or site conditions","Hard hat, safety glasses, and high-visibility apparel on active access routes","Gloves when handling rails, temporary stairs, or access materials","Lighting or headlamp where access routes are dim or temporary"]}]},{"id": "07","title": "Supported Scaffolding","ref": "Falls, Heights & Access   |   OSHA 29 CFR 1926.451","sections": [{"h": "SUMMARY","body": ["Supported scaffolds are safe only when properly built, inspected, accessed, and used within capacity. This talk focuses on competent-person inspection, full planking, guardrails, stable foundations, proper access, and dropped-object prevention."]},{"h": "IMPORTANT FACTS","body": ["Millions of construction workers use scaffolds. Scaffold incidents cause thousands of injuries and dozens of deaths each year, commonly involving platform failure, slips, or falling objects."]},{"h": "WHY IT MATTERS","body": ["About 2.3 million construction workers — roughly 65% of the trade — work on scaffolds. Scaffold incidents cause an estimated 4,500 injuries and 50 to 60 deaths every year. BLS found 72% of those injuries trace to just three causes: the planking or support giving way, a worker slipping, or being struck by a falling object — all preventable."]},{"h": "KEY HAZARDS","body": ["Improperly built or unlevel scaffolds without base plates and mudsills","Missing guardrails, incomplete planking, and platform gaps","Overloading beyond the rated capacity","Climbing cross-braces instead of using proper access","Contact with overhead power lines"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Scaffolds must be erected, moved, and dismantled under the supervision of a competent person.","Each scaffold and component must support its own weight plus at least 4x the maximum intended load.","Guardrails are required on platforms more than 10 ft above a lower level; toprail height 38–45 in.","Maintain at least 10 ft of clearance from energized power lines (more for higher voltages).","Fully plank platforms; gaps between planks and the uprights must be 1 in or less."]},{"h": "SAFE WORK PRACTICES","body": ["Confirm a green inspection tag (inspected by a competent person before each shift) — never use a red or missing tag.","Access platforms by ladder or stair tower — never climb the cross-bracing.","Keep platforms fully planked, guarded, and free of debris and excess material.","Keep loads within the rated capacity and evenly distributed.","Don't work on scaffolds in high wind, ice, or storms.","Report damaged, unlevel, or altered scaffolds immediately."]},{"h": "PPE NEEDED","body": ["Hard hat, safety glasses, high-visibility apparel, and safety-toe boots","Fall protection when scaffold rules, site policy, or exposure requires it","Tool lanyards when working above others","Task-specific gloves; hearing or respiratory protection when tools or dust require it"]}]},{"id": "08","title": "Aerial & Scissor Lifts","ref": "Falls, Heights & Access   |   OSHA 29 CFR 1926.453","sections": [{"h": "SUMMARY","body": ["Lifts create fall, tip-over, electrical, and crushing hazards when used beyond their limits. This talk reinforces authorized operators, pre-use inspection, firm level setup, boom-lift tie-off, overhead awareness, and staying inside the platform."]},{"h": "IMPORTANT FACTS","body": ["Leading lift deaths involve falls, tip-overs, and electrocutions. Boom-lift occupants must wear a harness tied to the boom, and bumping or driving into the lift can cause ejection deaths."]},{"h": "WHY IT MATTERS","body": ["Aerial (boom) lifts and scissor lifts cause tip-overs, ejections, electrocutions, and crushing. NIOSH finds most aerial-lift deaths involve falls or ejections from the platform, tip-overs, or contact with power lines. Many happen when the lift is bumped, driven onto uneven ground, or overloaded."]},{"h": "KEY HAZARDS","body": ["Tip-overs on uneven ground, slopes, or from overloading","Ejection when the boom moves or the vehicle is struck","Contact with overhead power lines and obstructions","Standing on rails or working with the gate/chain open","Crushing between the platform and overhead structure"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Only trained and authorized operators may use aerial lifts; retraining is required after any incident or unsafe operation.","Boom-lift occupants must wear a full-body harness with a lanyard attached to the boom/basket anchor.","Lift controls must be tested before each use; the manufacturer's load and reach limits must not be exceeded.","Maintain safe clearance from energized power lines per the minimum approach distances."]},{"h": "SAFE WORK PRACTICES","body": ["Complete the pre-use inspection of controls, alarms, and safety devices before operating.","Stand on the platform floor — never climb or sit on the guardrails; keep the gate/chain closed.","Set up on firm, level ground; deploy outriggers/stabilizers as required and check the slope.","Keep clear of power lines and overhead obstructions; treat all lines as energized.","Don't exceed the rated load or the platform capacity; watch for overhead crushing points.","Don't move a boom lift elevated unless it is designed and rated for it."]},{"h": "PPE NEEDED","body": ["Full-body harness and short lanyard attached to the manufacturer-approved anchor in boom lifts","Hard hat, safety glasses, high-visibility apparel, and safety-toe boots","Gloves for handling controls, materials, or tools","Hearing, respiratory, or face protection when the elevated task creates those hazards"]}]},{"id": "09","title": "Steel Erection","ref": "Falls, Heights & Access   |   OSHA 29 CFR 1926 Subpart R","sections": [{"h": "SUMMARY","body": ["Steel erection combines heights, cranes, rigging, decking, and structural stability risks. This talk centers on the erection plan, fall protection, controlled zones, qualified rigging/signaling, secured tools and bolts, and staying clear of suspended loads."]},{"h": "IMPORTANT FACTS","body": ["Fall protection is required at 15 feet in steel erection. Falls and struck-by loads are leading ironworker hazards, and columns require a minimum of four anchor bolts."]},{"h": "WHY IT MATTERS","body": ["Structural steel work combines heights, heavy hoisted loads, and connecting hazards. Falls and struck-by loads during erection are the leading causes of ironworker injury and death. Subpart R sets specific rules — including anchor-bolt minimums and controlled zones — to keep the structure and the crew stable during the most dangerous phase."]},{"h": "KEY HAZARDS","body": ["Falls while connecting, decking, and walking beams","Struck-by hoisted loads and rigging failures","Structural collapse from inadequate connections or bracing","Tripping and slipping on steel members and open decking"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Fall protection is required at 15 ft; connectors and workers in controlled decking zones follow the specific Subpart R provisions.","Columns must be anchored by a minimum of 4 anchor rods (bolts) and designed to resist specified loads.","A controlled decking zone (CDZ) may not exceed 90 ft wide by 90 ft deep without fall protection, per the plan.","Multiple lifts (\"Christmas-treeing\") require specific rigging and no more than five members per rigging assembly."]},{"h": "SAFE WORK PRACTICES","body": ["Follow the site-specific erection plan and your fall-protection plan for connectors.","Verify columns are properly anchored before loads are placed on the structure.","Stay clear of loads being hoisted; never ride the load or the hook.","Use qualified riggers and a signal person; inspect slings and shackles before each lift.","Keep bolts, tools, and materials secured to prevent drops on workers below.","Don't walk connections or beams until they are properly secured and bolted."]},{"h": "PPE NEEDED","body": ["Full-body harness, connectors, and approved anchorage when exposed to falls under the steel-erection plan","Hard hat with chin strap where required, safety glasses, gloves, and safety-toe boots","High-visibility apparel for crane and equipment operations","Tool lanyards and bolt bags to prevent dropped objects"]}]},{"id": "10","title": "Floor Openings & Guardrail Systems","ref": "Falls, Heights & Access   |   OSHA 29 CFR 1926.501(b) / .502","sections": [{"h": "SUMMARY","body": ["Floor openings, roof holes, skylights, and missing guardrails create preventable fall exposures for every trade. This talk reinforces covering, securing, labeling, inspecting, and replacing fall protection before anyone is exposed."]},{"h": "IMPORTANT FACTS","body": ["Unprotected edges and holes are a major fall source. Guardrails must withstand 200 pounds of force, and hole covers must support at least twice the expected load."]},{"h": "WHY IT MATTERS","body": ["Unprotected floor holes, wall openings, and open edges are one of the most common — and most preventable — fall exposures on any site. A guardrail system is often the simplest, most reliable protection because it protects everyone continuously without depending on each worker to tie off."]},{"h": "KEY HAZARDS","body": ["Uncovered floor holes, skylights, and roof openings","Wall openings with a 6-ft drop where the bottom edge is under 39 in","Weak, unsecured, or unmarked hole covers","Guardrails missing rails or not rated to withstand load"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Cover or guard every hole; covers must support at least 2x the weight of workers, equipment, and materials that may cross them.","Mark hole covers with \"HOLE\" or \"COVER\" and secure them against displacement.","Guardrails: toprail 42 in ±3, able to withstand 200 lb; mid-rail withstands 150 lb; toe boards where materials can fall.","Guard wall openings with a drop of 6 ft or more where the bottom edge is less than 39 in above the walking surface."]},{"h": "SAFE WORK PRACTICES","body": ["Cover and secure every floor hole and roof opening immediately when created.","Never remove a cover or guardrail without providing equivalent protection first.","Build guardrails to spec — top rail, mid-rail, and toe boards where needed.","Replace protection immediately after passing materials through an opening.","Inspect covers and rails at the start of each shift and after other trades work in the area.","Report any missing or damaged covers and rails to your supervisor at once."]},{"h": "PPE NEEDED","body": ["Fall protection when working near unprotected openings where guardrails or covers are not in place","Hard hat, safety glasses, high-visibility apparel, and safety-toe boots","Gloves for handling covers, rails, lumber, or metal edges","Tool lanyards when working above others or near openings"]}]},{"id": "11","title": "Personal Fall Arrest Systems & Training","ref": "Falls, Heights & Access   |   OSHA 29 CFR 1926.502 & .503","sections": [{"h": "SUMMARY","body": ["A personal fall arrest system only works when it is inspected, fitted, anchored, and backed by rescue planning. This talk reinforces harness inspection, proper anchorage, fall clearance, compatible connectors, training, and prompt rescue."]},{"h": "IMPORTANT FACTS","body": ["Fall protection training is a frequent OSHA violation. Anchors must hold 5,000 pounds per worker, the maximum arresting force is 1,800 pounds, and suspension trauma can become fatal within minutes."]},{"h": "WHY IT MATTERS","body": ["A harness only protects you if it fits, is anchored correctly, and you are trained to inspect and use it. Fall Protection — Training is itself one of OSHA's most-cited standards, meaning many workers wear systems they were never properly trained on. Correct anchoring, clearance, and a rescue plan are what turn a fall into a near-miss instead of a fatality."]},{"h": "KEY HAZARDS","body": ["Damaged, expired, or incompatible harnesses, lanyards, and connectors","Anchor points that cannot hold the required load","Excessive free-fall distance and swing-fall hazards","Improper fit or connecting to the wrong D-ring","No rescue plan for a suspended worker"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Anchorages must support 5,000 lb per attached worker, or be engineered to a 2:1 safety factor.","A PFAS must limit maximum arresting force to 1,800 lb, limit free fall to 6 ft (or less), and stop the fall within 3.5 ft.","Snap hooks and carabiners must be self-locking and compatible with what they connect to.","Employers must train each exposed worker in recognizing and minimizing fall hazards and using the systems."]},{"h": "SAFE WORK PRACTICES","body": ["Inspect the entire system — webbing, stitching, D-rings, buckles, snap hooks — before every use.","Anchor as directly overhead as possible to limit free fall and swing falls.","Connect the lanyard to the dorsal (back) D-ring and snug all straps for a proper fit.","Calculate total fall clearance below you (lanyard + deceleration + harness stretch + safety margin).","Remove any component from service permanently after it arrests a fall.","Have prompt rescue procedures and equipment ready before anyone goes up."]},{"h": "PPE NEEDED","body": ["Full-body harness sized to the worker and inspected before use","Shock-absorbing lanyard or self-retracting lifeline matched to fall clearance","Self-locking snap hooks/carabiners and approved anchorage","Hard hat, safety glasses, safety-toe boots, and rescue equipment staged before work"]}]},{"id": "12","title": "Hazard Communication & Safety Data Sheets","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1910.1200","sections": [{"h": "SUMMARY","body": ["Hazard Communication gives workers the information needed to use chemicals safely. This talk reinforces labels, SDS access, pictograms, compatible storage, spill response, and selecting PPE directly from the chemical’s hazards."]},{"h": "IMPORTANT FACTS","body": ["Hazard Communication is one of OSHA’s most-cited standards. About 30 million workers are exposed to hazardous chemicals, GHS uses nine pictograms, and every SDS follows a standard 16-section format."]},{"h": "WHY IT MATTERS","body": ["Hazard Communication is OSHA's second most-cited standard, year after year. Roughly 30 million U.S. workers are exposed to hazardous chemicals on the job. HazCom is built on your right to know: every chemical must be labeled, and a Safety Data Sheet must be available so you understand the hazards, the protection, and what to do in an emergency."]},{"h": "KEY HAZARDS","body": ["Unlabeled or improperly labeled containers","Skin, eye, inhalation, and ingestion exposure","Incompatible chemicals stored or used together","No ready access to Safety Data Sheets"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Every chemical container — including secondary/transfer containers — must be labeled with the identity and hazard.","GHS labels use 9 standardized pictograms and signal words (\"Danger\"/\"Warning\").","An SDS in the standard 16-section format must be readily accessible to workers on every shift.","Employers must maintain a written HazCom program and train workers on the chemicals in their area."]},{"h": "SAFE WORK PRACTICES","body": ["Read the GHS label and the SDS before using any chemical product.","Learn the 9 pictograms and what each hazard class means.","Keep every container labeled — never work from an unmarked bottle or bucket.","Know where the SDS library is (binder or app) and how to pull one fast.","Use the PPE the SDS specifies — gloves, eye protection, respirator.","Store incompatible chemicals separately, keep containers closed, and know spill/first-aid steps."]},{"h": "PPE NEEDED","body": ["Chemical-resistant gloves selected from the SDS","Safety glasses or chemical splash goggles; face shield for splash risk","Apron, sleeves, or disposable coveralls when skin contact is possible","Respirator only when required by the SDS and respiratory protection program"]}]},{"id": "13","title": "Respirable Crystalline Silica","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1926.1153","sections": [{"h": "SUMMARY","body": ["Silica dust is invisible at dangerous levels and can permanently damage lungs. This talk emphasizes Table 1 controls, wet methods, HEPA vacuums, respirator requirements, cleanup rules, and preventing dust from traveling home."]},{"h": "IMPORTANT FACTS","body": ["About 2.3 million workers are exposed to respirable crystalline silica, including roughly 2 million in construction. The PEL is 50 µg/m³ over 8 hours and the action level is 25 µg/m³."]},{"h": "WHY IT MATTERS","body": ["Cutting, grinding, drilling, and chipping concrete, brick, and stone release respirable crystalline silica — particles small enough to lodge deep in the lungs, where they cause silicosis, lung cancer, COPD, and kidney disease. About 2.3 million U.S. workers are exposed, most of them in construction. The disease is irreversible, but exposure is controllable."]},{"h": "KEY HAZARDS","body": ["Dust from cutting, grinding, chipping, and drilling masonry and concrete","Dry sweeping and cleanup that re-suspends settled dust","Abrasive blasting, tuckpointing, and demolition","Exposure without engineering controls or a proper respirator"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["The permissible exposure limit (PEL) is 50 µg/m³ as an 8-hour time-weighted average; the action level is 25 µg/m³.","Employers must follow Table 1 control methods (water/wet cutting or vacuum dust collection) for listed tasks, or do air monitoring.","A written exposure control plan is required, along with a designated competent person.","Medical surveillance must be offered to workers required to wear a respirator 30+ days a year."]},{"h": "SAFE WORK PRACTICES","body": ["Use the Table 1 control specified for your task — keep water on the blade or a HEPA vacuum shroud running.","Never dry sweep silica dust — use wet methods or a HEPA vacuum.","Wear the specified respirator when required, and be fit-tested and trained first.","Rotate tasks and limit time in high-dust areas where feasible.","Keep the written exposure control plan on site and follow it.","Wash hands and face before eating; don't carry dust home on clothing or in your vehicle."]},{"h": "PPE NEEDED","body": ["Assigned respirator, fit-tested and matched to the silica control plan","Safety glasses or goggles for cutting, grinding, or chipping","Gloves and long sleeves to limit dust and abrasion contact","Hearing protection when using saws, grinders, chipping tools, or compressors"]}]},{"id": "14","title": "Respiratory Protection","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1910.134","sections": [{"h": "SUMMARY","body": ["A respirator only protects you if it is the right type for the hazard, fits your face, and is maintained. This talk covers medical clearance and annual fit testing, matching the cartridge to the contaminant, being clean-shaven at the seal, performing a user seal check every time, and never using an air-purifying respirator in an oxygen-deficient or IDLH atmosphere."]},{"h": "IMPORTANT FACTS","body": ["Respiratory protection is a frequent OSHA violation. Oxygen-deficient means below 19.5% oxygen, fit testing is required at least annually, and facial hair at the seal defeats the respirator."]},{"h": "WHY IT MATTERS","body": ["Respiratory Protection is consistently one of OSHA's most-cited standards. A respirator only protects you if it is the right type for the hazard, fits your face, and is maintained — anything less gives a dangerous false sense of security. The wrong respirator in an oxygen-deficient or IDLH atmosphere can be fatal."]},{"h": "KEY HAZARDS","body": ["Dusts, fumes, mists, vapors, and gases","Oxygen-deficient atmospheres (below 19.5% O₂)","Wrong respirator or cartridge for the hazard","Poor face seal from facial hair or improper fit","Contaminated or poorly maintained respirators"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["A medical evaluation is required before a worker may be fit-tested or wear a tight-fitting respirator.","Fit testing is required before first use and at least annually thereafter.","The respirator and cartridge must be matched to the specific contaminant and its concentration.","Air-purifying respirators must NOT be used in oxygen-deficient or IDLH atmospheres — use supplied air/SCBA."]},{"h": "SAFE WORK PRACTICES","body": ["Be medically cleared and fit-tested before using a tight-fitting respirator.","Be clean-shaven where the respirator seals — facial hair breaks the seal.","Perform a user seal check (positive and negative) every time you put it on.","Match the cartridge to the hazard (particulate vs. organic vapor vs. acid gas).","Inspect for damaged straps, valves, and cartridges; replace on schedule.","Store respirators clean, in a sealed bag, away from dust, heat, and sunlight."]},{"h": "PPE NEEDED","body": ["NIOSH-approved respirator selected for the contaminant and concentration","Correct cartridges, filters, or supplied-air/SCBA equipment for the atmosphere","Clean storage bag or container for reusable respirators","Eye, face, glove, or protective clothing as required by the exposure task"]}]},{"id": "15","title": "Occupational Noise & Hearing Conservation","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1926.52 / 1910.95","sections": [{"h": "SUMMARY","body": ["Noise damage happens gradually and cannot be repaired. This talk reinforces recognizing harmful noise, using plugs or muffs correctly, double protection for high-noise tasks, equipment maintenance, and reporting ringing or muffled hearing early."]},{"h": "IMPORTANT FACTS","body": ["About 22 million workers are exposed to hazardous noise each year. The PEL is 90 dBA over 8 hours, the action level is 85 dBA, and noise-induced hearing loss is permanent."]},{"h": "WHY IT MATTERS","body": ["About 22 million U.S. workers are exposed to hazardous noise on the job each year, and noise-induced hearing loss is permanent and 100% preventable. A simple test: if you must raise your voice to be heard by someone an arm's length away, the noise is likely at a harmful level. Damage is painless and gradual — you won't feel it happening."]},{"h": "KEY HAZARDS","body": ["Continuous equipment and generator noise","Impact noise from nailing, hammering, and demolition","Long exposure without hearing protection","The false belief that you'll \"get used to\" loud noise (that feeling is damage)"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["The permissible exposure limit is 90 dBA as an 8-hour time-weighted average.","At the 85 dBA action level, a hearing conservation program (monitoring, testing, protection, training) is required.","Feasible engineering or administrative controls must be used before relying on PPE where the PEL is exceeded.","Audiometric (hearing) testing must be provided to workers in the program at no cost."]},{"h": "SAFE WORK PRACTICES","body": ["Wear hearing protection (plugs or muffs) in all posted high-noise areas.","Use double protection (plugs + muffs) for very loud tasks like jackhammering.","Insert foam plugs correctly — roll them down, pull the ear up and back, insert, and hold to expand.","Rotate tasks and take breaks from noise to reduce total exposure.","Keep equipment maintained; worn parts and loose panels raise noise levels.","Report any ringing (tinnitus) or muffled hearing — early signs of damage."]},{"h": "PPE NEEDED","body": ["Earplugs, earmuffs, or both where noise levels require protection","Properly fitted foam plugs or reusable plugs kept clean and available","Double hearing protection for very loud impact or demolition work","Hard hat, safety glasses, gloves, and safety-toe boots for the task"]}]},{"id": "16","title": "Lead in Construction","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1926.62","sections": [{"h": "SUMMARY","body": ["Lead exposure can harm workers and their families through dust carried home on clothes, skin, and vehicles. This talk reinforces assuming older coatings may contain lead, using controls, respiratory protection, hygiene, change-out, and blood-lead monitoring."]},{"h": "IMPORTANT FACTS","body": ["The lead PEL is 50 µg/m³ over 8 hours and the action level is 30 µg/m³. Lead is also a take-home hazard for families, and pre-1978 paint should be treated as lead-containing until confirmed otherwise."]},{"h": "WHY IT MATTERS","body": ["Renovation, demolition, welding, and repainting of older structures can release lead dust and fumes. Lead damages the nervous system, kidneys, and blood — and workers routinely carry it home on skin, clothes, and vehicles, poisoning their own children. Effects build silently over time, so controls and monitoring matter even when you feel fine."]},{"h": "KEY HAZARDS","body": ["Dust and fumes from sanding, cutting, burning, welding, or blasting lead paint","Ingestion from eating, drinking, or smoking with contaminated hands","Take-home exposure on clothing, skin, hair, and vehicles","Old painted steel, bridges, and pre-1978 buildings"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["The PEL is 50 µg/m³ as an 8-hour TWA; the action level is 30 µg/m³.","Presume lead is present on listed tasks until exposure monitoring shows otherwise.","Blood-lead monitoring and medical surveillance are required for workers exposed at/above the action level.","Provide clean change areas, hand-washing, and separate storage so lead isn't carried home."]},{"h": "SAFE WORK PRACTICES","body": ["Assume paint on older structures contains lead until testing proves otherwise.","Use engineering controls (HEPA vacuums, wet methods) to minimize dust and fumes.","Wear the required respirator and disposable coveralls for lead tasks.","Wash hands and face before eating, drinking, or smoking — never in the work area.","Change out of contaminated clothing before going home; never launder it with family clothes.","Participate in blood-lead monitoring and keep lead debris contained and properly disposed of."]},{"h": "PPE NEEDED","body": ["Assigned respirator and filters based on exposure assessment","Disposable coveralls, gloves, and boot covers for lead-disturbing work","Safety glasses or goggles; face shield for blasting, grinding, or splash risk","Dedicated change-out and hygiene supplies to prevent take-home exposure"]}]},{"id": "17","title": "Asbestos Awareness","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1926.1101","sections": [{"h": "SUMMARY","body": ["Asbestos hazards are often hidden in older materials and can cause disease decades later. This talk reinforces recognizing suspect materials, stopping work, avoiding disturbance, using trained abatement personnel, and following decontamination and disposal controls."]},{"h": "IMPORTANT FACTS","body": ["There is no safe level of asbestos exposure. The asbestos PEL is 0.1 fibers/cc over 8 hours, disease can appear 10–40 years later, and pre-1980 building materials should be treated as suspect until verified."]},{"h": "WHY IT MATTERS","body": ["Asbestos in older insulation, floor tile, mastic, joint compound, and roofing releases microscopic fibers when disturbed. Those fibers cause mesothelioma, lung cancer, and asbestosis — often decades after exposure. There is no safe level, so the rule is simple: don't disturb suspect materials, and stop work if you find them."]},{"h": "KEY HAZARDS","body": ["Damaged or disturbed asbestos-containing materials (ACM)","Pipe/boiler insulation, floor tile, mastic, joint compound, roofing, siding","Dry removal, cutting, and demolition that releases fibers","Untrained workers disturbing suspect materials"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["The PEL is 0.1 fibers per cubic centimeter as an 8-hour TWA (with a 30-minute excursion limit of 1.0 f/cc).","Work is divided into Classes I–IV; only trained, licensed workers may disturb or remove ACM.","Regulated areas, negative-pressure enclosures, and wet methods are required for higher-class work.","Suspect materials in buildings constructed before 1981 must be presumed to be asbestos-containing until tested."]},{"h": "SAFE WORK PRACTICES","body": ["Treat suspect materials in older buildings as asbestos until testing proves otherwise.","Stop work and notify your supervisor if you find or accidentally damage suspect material.","Never sand, cut, grind, or dry-sweep suspect materials.","Only licensed abatement workers disturb or remove ACM, using wet methods and required PPE.","Follow proper bagging, labeling, and disposal for asbestos waste.","Decontaminate before leaving a regulated area."]},{"h": "PPE NEEDED","body": ["Asbestos-rated respirator and protective clothing only for trained/authorized asbestos work","Disposable coveralls, gloves, boot covers, and decontamination supplies when assigned","Safety glasses or goggles as required by the task","Do not use PPE as permission to disturb suspect material unless trained and authorized"]}]},{"id": "18","title": "Heat Illness Prevention","ref": "Health & Environmental Hazards   |   OSHA Heat NEP / OSH Act General Duty Clause","sections": [{"h": "SUMMARY","body": ["Heat illness can become fatal quickly, especially for new or returning workers. This talk reinforces water, rest, shade, acclimatization, buddy checks, early symptoms, emergency response, and adjusting work when heat conditions rise."]},{"h": "IMPORTANT FACTS","body": ["Heat is the leading cause of weather-related worker deaths, and worker heat fatalities have risen roughly 70% over the past decade. BLS recorded 48 work-related deaths from environmental heat in 2024, a figure widely regarded as an undercount. OSHA's Heat National Emphasis Program, updated in April 2026, now directs inspections toward 55 high-risk industries. Most heat deaths strike workers in their first days on the job, before they are acclimatized."]},{"h": "WHY IT MATTERS","body": ["Heat is the leading cause of weather-related worker deaths, and worker heat fatalities have climbed roughly 70% over the past decade. OSHA's National Emphasis Program for heat — updated in April 2026 and now covering 55 high-risk industries — directs inspections toward this hazard. Critically, most heat deaths strike workers in their first few days on the job, before their bodies have acclimatized."]},{"h": "KEY HAZARDS","body": ["High temperature and humidity, especially early season before acclimatization","Direct sun and radiant heat from roofing, asphalt, and metal","Dehydration and skipping water and rest breaks","Heavy PPE and physically demanding work","New or returning workers who are not yet acclimatized"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Under the General Duty Clause and the Heat NEP, employers must protect workers from recognized heat hazards.","OSHA guidance calls for water, rest, shade, and a gradual acclimatization schedule for new/returning workers.","Employers should have a heat plan that ramps exposure over the first 1–2 weeks and monitors conditions.","Heat stroke (confusion, no sweating, collapse) is a medical emergency — call 911 immediately."]},{"h": "SAFE WORK PRACTICES","body": ["Drink water often — about 1 cup every 15–20 minutes; don't wait until you're thirsty.","Take rest breaks in shade or a cool area, and increase breaks as the heat index rises.","Acclimatize new and returning workers gradually over the first 1–2 weeks — this is the single biggest lifesaver.","Watch coworkers for heavy sweating, headache, dizziness, cramps, nausea, or confusion.","Treat confusion, hot/dry skin, or fainting as heat stroke — call 911 and cool the person immediately.","Wear light, breathable clothing; avoid energy drinks and heavy caffeine, which worsen dehydration."]},{"h": "PPE NEEDED","body": ["Lightweight, breathable clothing suitable for the task and site rules","Cooling towel, cooling vest, shade hat, or sun protection where allowed","Hydration supplies and electrolyte replacement when sweating heavily","Task-required hard hat, safety glasses, gloves, high-visibility apparel, and boots"]}]},{"id": "19","title": "Cold Stress","ref": "Health & Environmental Hazards   |   OSHA OSH Act General Duty Clause","sections": [{"h": "SUMMARY","body": ["Cold stress affects judgment, dexterity, and body temperature before workers may realize it. This talk reinforces layered clothing, dry gloves and socks, warm-up breaks, wind chill awareness, frostbite recognition, and emergency response for hypothermia."]},{"h": "IMPORTANT FACTS","body": ["Cold stress does not require sub-freezing temperatures. Wind chill and wet clothing pull body heat away far faster than air temperature alone suggests, and the body loses heat many times faster when wet than when dry. Cold also stiffens hands and slows reaction time, which drives up slips, dropped loads, and other secondary injuries."]},{"h": "WHY IT MATTERS","body": ["Cold-weather work brings hypothermia, frostbite, and trench foot. Wind chill and wet clothing pull body heat away far faster than air temperature alone suggests, and can turn a merely cold day into a medical emergency. Cold also stiffens hands and slows reactions, driving up slips, drops, and other injuries."]},{"h": "KEY HAZARDS","body": ["Low temperatures combined with wind and wet clothing","Prolonged exposure without warm-up breaks","Frostbite to fingers, toes, ears, and nose","Reduced dexterity and slower reactions leading to secondary injuries"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Under the General Duty Clause, employers must protect workers from recognized cold hazards.","Provide warm-up breaks, heated areas, and a schedule that limits continuous cold exposure.","Recognize the warning signs of hypothermia and frostbite and have a response plan.","Provide appropriate cold-weather PPE and dry replacements."]},{"h": "SAFE WORK PRACTICES","body": ["Dress in layers with an insulating layer and a windproof/waterproof outer shell.","Stay dry — change out of wet clothing and gloves promptly.","Take breaks in a heated area and drink warm, non-caffeinated fluids.","Cover exposed skin and wear insulated, non-slip footwear.","Watch for shivering, numbness, pale or waxy skin, slurred speech, and confusion.","Warm affected areas gradually and get medical help for suspected frostbite or hypothermia."]},{"h": "PPE NEEDED","body": ["Layered cold-weather clothing with windproof and waterproof outer shell","Insulated gloves, dry replacement gloves, and warm head/ear protection under hard hat where compatible","Insulated, slip-resistant safety-toe boots with dry socks","High-visibility outerwear suitable for low light or snow conditions"]}]},{"id": "20","title": "Bloodborne Pathogens","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1910.1030","sections": [{"h": "SUMMARY","body": ["Bloodborne pathogen exposure can occur during first aid, cleanup, or contact with sharps. This talk reinforces universal precautions, gloves and eye protection, CPR barriers, safe sharps handling, handwashing, reporting exposures, and follow-up care."]},{"h": "IMPORTANT FACTS","body": ["The primary bloodborne pathogens are hepatitis B (HBV), hepatitis C (HCV), and HIV. HBV can survive in dried blood on surfaces for at least seven days and is far more transmissible through a needlestick than HIV. OSHA requires employers to offer the hepatitis B vaccine at no cost to workers with occupational exposure and to treat all blood and bodily fluids as infectious."]},{"h": "WHY IT MATTERS","body": ["First-aid responders and workers who may contact blood or bodily fluids risk infection from hepatitis B, hepatitis C, and HIV. Simple, consistent precautions dramatically cut that risk. Because you can't tell by looking whether a fluid is infectious, the rule is to treat all blood and bodily fluids as if they are."]},{"h": "KEY HAZARDS","body": ["Contact with blood or bodily fluids during first aid","Needlesticks and cuts from contaminated sharps","Splashes to the eyes, nose, or mouth","Cleaning up after an injury without protection"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Employers with occupational exposure must have a written Exposure Control Plan, reviewed annually.","The hepatitis B vaccine must be offered at no cost to workers with occupational exposure.","PPE, sharps containers, and labeling of biohazard materials must be provided.","Exposure incidents require prompt confidential medical evaluation and follow-up."]},{"h": "SAFE WORK PRACTICES","body": ["Treat all blood and bodily fluids as if infectious (universal precautions).","Wear gloves and eye protection when providing first aid or cleaning spills.","Use provided barriers/CPR shields when giving aid.","Never pick up broken glass or sharps by hand — use tools and a sharps container.","Wash exposed skin with soap and water immediately after any contact.","Report every exposure incident right away for medical follow-up."]},{"h": "PPE NEEDED","body": ["Disposable medical gloves for first aid or cleanup","Safety glasses, goggles, or face shield for splash potential","CPR shield or barrier device when providing rescue breaths","Biohazard bags, sharps container, and handwashing/sanitizing supplies"]}]},{"id": "21","title": "Carbon Monoxide & Air Contaminants","ref": "Health & Environmental Hazards   |   OSHA 29 CFR 1926.55","sections": [{"h": "SUMMARY","body": ["Carbon monoxide and air contaminants can build up without warning, especially around combustion equipment. This talk reinforces ventilation, monitoring, keeping engines outdoors, recognizing symptoms, evacuating on alarms, and treating fresh air as the first control."]},{"h": "IMPORTANT FACTS","body": ["Carbon monoxide is colorless, odorless, and tasteless — it cannot be detected without a monitor. OSHA's permissible exposure limit is 50 ppm over 8 hours, but a gas engine running in an enclosed space can drive concentrations into the thousands of ppm within minutes, which is rapidly fatal. Early symptoms — headache, dizziness, nausea — are routinely mistaken for ordinary fatigue."]},{"h": "WHY IT MATTERS","body": ["Carbon monoxide from gas and propane engines and heaters is colorless and odorless, and it can kill within minutes in an enclosed space. Fuel-powered saws, generators, pressure washers, and heaters are everywhere on a site — and every one is deadly indoors or in a poorly ventilated area. Early symptoms mimic simple fatigue, so workers often don't realize the danger until it's severe."]},{"h": "KEY HAZARDS","body": ["Gas/propane engines, generators, and heaters used indoors or in enclosed areas","Exhaust buildup in basements, tanks, and partially enclosed structures","Symptoms (headache, dizziness, nausea) mistaken for fatigue","Combustion equipment placed near air intakes"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["OSHA's PEL for carbon monoxide is 50 ppm as an 8-hour TWA.","Fuel-powered equipment must not be operated in enclosed/poorly ventilated spaces without adequate controls.","Provide ventilation and, where CO may accumulate, continuous CO monitoring with alarms.","Air contaminants under 1926.55 must be kept below their listed exposure limits."]},{"h": "SAFE WORK PRACTICES","body": ["Never run gas engines, generators, or fuel heaters indoors or in enclosed spaces.","Use electric or pneumatic tools instead of gas-powered ones inside buildings.","Ventilate the area and point exhaust away from workers and air intakes.","Use CO monitors in enclosed or questionable spaces and evacuate on alarm.","Recognize CO symptoms — headache, dizziness, nausea, confusion — and get to fresh air.","Move anyone with symptoms to fresh air immediately and call 911."]},{"h": "PPE NEEDED","body": ["Personal or area CO monitor where combustion equipment or enclosed spaces are involved","Respiratory protection only when selected by the exposure assessment and program","Hard hat, safety glasses, gloves, high-visibility apparel, and safety-toe boots","Do not rely on PPE alone; ventilation, monitoring, and fresh air are primary controls"]}]},{"id": "22","title": "Lockout/Tagout — Control of Hazardous Energy","ref": "Equipment, Machinery & Energy Control   |   OSHA 29 CFR 1910.147","sections": [{"h": "SUMMARY","body": ["Lockout/tagout prevents unexpected startup and release of stored energy during service work. This talk reinforces identifying all energy sources, applying personal locks, releasing stored energy, verifying zero energy, and never removing another worker’s lock."]},{"h": "IMPORTANT FACTS","body": ["OSHA estimates that proper lockout/tagout prevents roughly 120 deaths and 50,000 injuries every year. About 3 million U.S. workers service or maintain equipment capable of releasing hazardous energy. LOTO (1910.147) is consistently a top-five most-cited standard, drawing 2,655 citations in FY2024, and failures typically produce amputations, crushing injuries, burns, or electrocution."]},{"h": "WHY IT MATTERS","body": ["OSHA estimates that proper lockout/tagout prevents about 120 deaths and 50,000 injuries every year. Roughly 3 million workers service or maintain equipment that can release hazardous energy, and LOTO is consistently a top-five most-cited standard. When energy isn't isolated, the injuries are catastrophic: amputations, crushing, burns, and electrocution."]},{"h": "KEY HAZARDS","body": ["Unexpected machine startup during service or clearing jams","Stored energy in springs, hydraulics, air, steam, and capacitors","Working without isolating every energy source","Another worker re-energizing equipment you're servicing"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Only authorized employees perform lockout; affected employees must be notified before and after.","Each energy source must be isolated, and each worker applies their own lock and tag.","Stored/residual energy must be released, blocked, or dissipated before work begins.","Zero-energy state must be verified by attempting to operate the controls, then returning them to off.","Only the worker who applied a lock may remove it (except under a documented removal procedure)."]},{"h": "SAFE WORK PRACTICES","body": ["Identify all energy sources — electrical, hydraulic, pneumatic, mechanical, thermal, gravity.","Shut down, isolate, and apply your own lock and tag to each source.","Bleed lines, discharge capacitors, and block suspended parts to release stored energy.","Verify zero energy by trying to start the equipment before you reach in.","Never remove someone else's lock; follow the group-lockout procedure for multi-worker jobs.","Re-verify isolation any time you leave and return to the task."]},{"h": "PPE NEEDED","body": ["Personal lock, tag, and hasp assigned to the worker","Voltage-rated gloves, face shield, or arc-rated PPE when electrical verification requires it","Safety glasses, hard hat, gloves, and safety-toe boots","Task-specific PPE for released pressure, fluids, heat, or stored energy"]}]},{"id": "23","title": "Powered Industrial Trucks / Forklifts","ref": "Equipment, Machinery & Energy Control   |   OSHA 29 CFR 1910.178","sections": [{"h": "SUMMARY","body": ["Forklifts create serious risks for operators, pedestrians, loads, and docks. This talk reinforces authorized operation, pre-shift inspection, seat belts, traveling with loads low, pedestrian separation, stable stacking, and safe fueling or charging."]},{"h": "IMPORTANT FACTS","body": ["Forklift incidents cause dozens of deaths and thousands of serious injuries each year. Tip-overs are a leading fatal event, and operator training, pre-shift inspections, seat belt use, and pedestrian separation prevent most incidents."]},{"h": "WHY IT MATTERS","body": ["Forklifts and other powered industrial trucks cause roughly 85 deaths and more than 34,000 serious injuries in U.S. workplaces every year. Tip-overs alone account for about 42% of forklift fatalities. OSHA estimates that around 70% of these accidents could be prevented with proper operator training and evaluation."]},{"h": "KEY HAZARDS","body": ["Tip-overs from overloading, uneven loads, raised loads, or fast turns","Pedestrians struck in blind spots and at intersections","Falling loads and unstable stacking","Carbon monoxide from propane/gas trucks used indoors"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Only trained, evaluated, and authorized operators may operate a PIT.","Operator performance must be re-evaluated at least every 3 years, and retraining given after any incident or unsafe operation.","A pre-shift inspection is required; trucks with defects must be taken out of service.","Load capacity on the data plate must never be exceeded."]},{"h": "SAFE WORK PRACTICES","body": ["Complete the pre-shift inspection and tag out any truck with defects.","Keep loads within capacity, tilted back, and low while traveling.","Sound the horn at intersections and blind corners; slow down and watch for pedestrians.","Never let anyone stand or walk under raised forks or ride as a passenger.","Travel in reverse when the load blocks your view; keep clear of edges and docks.","Set the brake, lower the forks, neutralize controls, and shut off before dismounting."]},{"h": "PPE NEEDED","body": ["Seat belt/restraint when operating the truck","High-visibility apparel for pedestrians and spotters near forklift traffic","Safety-toe footwear and hard hat where overhead loads are present","Gloves and eye protection for battery charging, fueling, or load handling"]}]},{"id": "24","title": "Machine Guarding","ref": "Equipment, Machinery & Energy Control   |   OSHA 29 CFR 1910.212","sections": [{"h": "SUMMARY","body": ["Machine guarding protects workers from fast-moving points of operation, rotating parts, and nip points. This talk reinforces keeping guards in place, removing defective equipment, locking out before service, avoiding loose items, and using tools instead of hands near danger zones."]},{"h": "IMPORTANT FACTS","body": ["Machine-guarding failures can cause amputations and severe lacerations in a fraction of a second. Guards are the physical barrier that keeps hands, clothing, and tools out of the danger zone."]},{"h": "WHY IT MATTERS","body": ["Machine Guarding is one of OSHA's most-cited standards, and for good reason: unguarded blades, gears, belts, and rotating parts amputate and lacerate in a fraction of a second — faster than any worker can pull away. A guard is a simple, permanent barrier that keeps the point of operation and moving parts out of reach."]},{"h": "KEY HAZARDS","body": ["Points of operation — blades, bits, and cutting edges","Rotating shafts, gears, pulleys, belts, and couplings","Flying chips, sparks, and ejected material","In-running nip points and pinch points"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Guards are required at the point of operation, nip points, rotating parts, and where sparks/chips are thrown.","Guards must be securely attached and not create a hazard themselves (no new pinch points).","Point-of-operation guarding must prevent the operator from having any body part in the danger zone during operation.","Anchor fixed machinery to prevent \"walking\" and provide guarding for power transmission apparatus."]},{"h": "SAFE WORK PRACTICES","body": ["Never operate a machine or tool with a guard removed, adjusted away, or defeated.","Keep guards in place on saws, grinders, and rotating equipment.","Lock out power before adjusting, cleaning, or clearing a jam.","Keep hands, tools, and clothing away from moving parts; use push sticks/blocks where provided.","Tie back long hair and avoid loose clothing, gloves, and jewelry near rotating parts.","Report missing or damaged guards and take the equipment out of service."]},{"h": "PPE NEEDED","body": ["Safety glasses or face shield for chips, sparks, or flying material","Hearing protection where machine noise requires it","No loose gloves, jewelry, sleeves, or hair near rotating parts","Cut-resistant gloves only when handling material away from rotating equipment"]}]},{"id": "25","title": "Cranes & Rigging","ref": "Equipment, Machinery & Energy Control   |   OSHA 29 CFR 1926 Subpart CC","sections": [{"h": "SUMMARY","body": ["Crane and rigging work can expose multiple workers to one high-consequence failure. This talk reinforces lift planning, power-line clearance, qualified operators, riggers and signal persons, inspected rigging, barricaded swing radius, tag lines, and staying out from under loads."]},{"h": "IMPORTANT FACTS","body": ["Power-line contact, dropped loads, rigging failures, and tip-overs are leading crane hazards. Safe lifts depend on qualified people, inspected gear, controlled swing areas, and maintaining required clearances."]},{"h": "WHY IT MATTERS","body": ["Crane operations combine massive loads, moving equipment, and overhead hazards, and a single failure can kill several workers at once. Contact with overhead power lines is the leading cause of crane-related deaths, followed by dropped loads, rigging failures, and tip-overs. Planning, ground preparation, and qualified people are what keep these lifts safe."]},{"h": "KEY HAZARDS","body": ["Contact with overhead power lines","Dropped or swinging loads and rigging failures","Crane tip-over from overloading or unstable ground","Struck-by and crushing within the swing radius"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Maintain at least 20 ft clearance from power lines up to 350 kV (more above that) unless de-energized and grounded.","Crane operators must be certified/qualified, and a qualified rigger and designated signal person are required for lifts.","The crane must be set on firm, level ground with outriggers/mats deployed per the manufacturer.","Rated capacity (load chart) must never be exceeded; slings and hardware must be inspected before each use."]},{"h": "SAFE WORK PRACTICES","body": ["Know the load weight and confirm the lift is within the load chart before hoisting.","Keep the required clearance from power lines; use a dedicated spotter near lines.","Inspect slings, shackles, and hooks before each lift; look for cuts, wear, and deformation.","Barricade the swing radius and keep everyone out from under the load.","Use tag lines to control the load — never ride the load or the hook.","Stop the lift for high wind, poor visibility, or any unsafe condition."]},{"h": "PPE NEEDED","body": ["Hard hat, safety glasses, high-visibility apparel, and safety-toe boots","Gloves suited for rigging inspection and handling","Tag lines and tool lanyards where dropped-object risk exists","Fall protection when rigging or signaling from elevated locations"]}]},{"id": "26","title": "Hand & Power Tools","ref": "Equipment, Machinery & Energy Control   |   OSHA 29 CFR 1926 Subpart I","sections": [{"h": "SUMMARY","body": ["Hand and power tools cause frequent injuries when damaged, misused, or operated without guards. This talk reinforces inspection, correct tool selection, guarding, eye and face protection, disconnecting power before changes, and keeping hands clear of cutting points."]},{"h": "IMPORTANT FACTS","body": ["Hand and power tools frequently cause cuts, punctures, struck-by injuries, and flying-particle exposure. Most incidents trace back to damaged tools, missing guards, or using the wrong tool for the task."]},{"h": "WHY IT MATTERS","body": ["Hand and power tools are used constantly, and they cause frequent cuts, punctures, and struck-by injuries — over 223,000 hand-tool injuries were reported in a single recent year. Most incidents trace back to damaged tools, missing guards, or simply using the wrong tool for the job."]},{"h": "KEY HAZARDS","body": ["Damaged tools, frayed cords, and missing or wired-back guards","Using the wrong tool for the task","Flying particles and kickback","Point-of-operation contact and pinch points"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Employers and workers must maintain tools in safe condition; defective tools must be removed from service.","Guards on power tools (saws, grinders) must be in place and functional; never wire back a guard.","Power tools must be grounded, double-insulated, or powered by an isolating transformer.","Use the correct guarding and PPE for the specific tool and task."]},{"h": "SAFE WORK PRACTICES","body": ["Inspect tools and cords before use; remove damaged or defective tools from service.","Use the right tool for the job, rated for the task, and use it as designed.","Keep guards in place and never bypass safety devices or triggers.","Wear eye/face protection and secure loose clothing, gloves, and jewelry.","Keep cutting edges sharp and cut away from your body.","Disconnect power before changing blades, bits, or accessories; never carry a tool by the cord."]},{"h": "PPE NEEDED","body": ["Safety glasses with side shields; face shield for grinding, cutting, or chipping","Task-appropriate gloves, avoiding gloves near rotating parts","Hearing protection for loud tools and impact work","Respiratory protection when dust, fumes, or silica controls require it"]}]},{"id": "27","title": "Powder-Actuated Tools","ref": "Equipment, Machinery & Energy Control   |   OSHA 29 CFR 1926.302","sections": [{"h": "SUMMARY","body": ["Powder-actuated tools behave like construction firearms and require trained operators. This talk reinforces certification, tool inspection, correct loads and fasteners, bystander control, misfire response, locked storage, and eye and hearing protection."]},{"h": "IMPORTANT FACTS","body": ["Fasteners can pass through or ricochet off base material, operators must be certified on the specific tool, and a misfire requires holding the tool against the surface for at least 30 seconds before following the manufacturer’s procedure."]},{"h": "WHY IT MATTERS","body": ["Powder-actuated fastening tools fire fasteners using an explosive charge, essentially a firearm for construction. Misfires, ricochets, and fasteners driving through the base material can seriously injure or kill the operator and bystanders — including people on the far side of a wall being fastened."]},{"h": "KEY HAZARDS","body": ["Fasteners passing through or ricocheting off the base material","Accidental discharge and misfires","Firing into unsuitable materials (brittle, very hard, or thin)","Untrained operators and unaware bystanders"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Only operators trained and certified for the specific tool may use it (certification card carried on them).","The tool must not fire unless pressed against the work surface with the required force.","Do not fire into brittle, very hard, or easily penetrated materials, or closer than the manufacturer's edge distance.","On a misfire, hold the tool against the surface for at least 30 seconds before following the manufacturer's steps."]},{"h": "SAFE WORK PRACTICES","body": ["Confirm you're certified on the exact tool before using it.","Inspect the tool before use and verify it won't fire unless pressed to the surface.","Never point the tool at anyone; keep bystanders clear, including behind the wall.","Select the correct charge and fastener for the base material.","Wear eye and hearing protection.","Store tools and charges locked and separated when not in use."]},{"h": "PPE NEEDED","body": ["Safety glasses plus face shield for ricochet or flying-fragment exposure","Hearing protection for every firing operation","Hard hat, safety-toe boots, and gloves for handling fasteners and materials","High-visibility apparel if used around other equipment or traffic"]}]},{"id": "28","title": "Compressed Gas Cylinders","ref": "Equipment, Machinery & Energy Control   |   OSHA 29 CFR 1926.350","sections": [{"h": "SUMMARY","body": ["Compressed gas cylinders are high-pressure energy sources that can become projectiles or fuel fires. This talk reinforces upright secure storage, valve caps, cylinder carts, separating oxygen and fuel gas, leak checks, and safe hot-work support."]},{"h": "IMPORTANT FACTS","body": ["A broken valve can turn a cylinder into a projectile. Oxygen and fuel-gas cylinders must be stored 20 feet apart, or separated by a rated firewall, and all cylinders must be secured upright at all times."]},{"h": "WHY IT MATTERS","body": ["Compressed gas cylinders store large amounts of energy under high pressure. If a cylinder tips and the valve snaps off, it can rocket through walls and people like a torpedo. Leaking fuel gases add fire and explosion risk. Simple storage and handling rules prevent nearly all cylinder incidents."]},{"h": "KEY HAZARDS","body": ["Valve damage turning a cylinder into a projectile","Fire and explosion from fuel-gas leaks","Cylinders falling and crushing hands and feet","Mixing incompatible gases (oxygen with fuel gases)"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Cylinders must be secured upright with a chain or strap at all times, in use and in storage.","Valve protection caps must be in place when cylinders are not connected and in use.","Store oxygen and fuel-gas cylinders at least 20 ft apart, or separated by a 5-ft noncombustible barrier with a ½-hour fire rating.","Cylinders must be kept away from heat sources and never used as rollers or supports."]},{"h": "SAFE WORK PRACTICES","body": ["Secure cylinders upright and keep protection caps on when not in use.","Never lift cylinders by the valve cap; use a cart or cradle to move them.","Store oxygen and fuel gases the required distance apart.","Keep cylinders away from heat, sparks, flame, and electrical circuits.","Check for leaks with soapy water — never a flame.","Close valves and bleed lines when finished; mark empties \"MT.\""]},{"h": "PPE NEEDED","body": ["Safety glasses, gloves, and safety-toe boots when moving or connecting cylinders","Face shield and flame-resistant PPE for cutting, welding, or brazing tasks","Cylinder cart, chains, straps, and valve caps for safe movement/storage","Respiratory protection only when the work area exposure assessment requires it"]}]},{"id": "29","title": "Excavation & Trenching","ref": "Excavation & Confined Spaces   |   OSHA 29 CFR 1926 Subpart P","sections": [{"h": "SUMMARY","body": ["Excavation hazards can bury, strike, or expose workers to utilities and atmospheres. This talk reinforces competent-person inspections, protective systems at depth, spoil-pile setbacks, safe access, utility locating, water control, and atmospheric testing when needed."]},{"h": "IMPORTANT FACTS","body": ["One cubic yard of soil can weigh about 3,000 pounds. Protective systems are required at 5 feet deep, and trench collapses have caused hundreds of deaths since 2013."]},{"h": "WHY IT MATTERS","body": ["A cubic yard of soil weighs about 3,000 pounds — as much as a small car — and a trench wall collapses faster than a worker can climb out. More than 250 workers have died in trench collapses since 2013, with deaths spiking to 39 in 2022. Protective systems and a competent person are what stand between a routine dig and a burial."]},{"h": "KEY HAZARDS","body": ["Cave-ins in trenches 5 ft or deeper (and shallower unstable soil)","Falls into the excavation and struck-by falling loads","Hazardous atmospheres and water accumulation","Contact with underground and overhead utilities"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["A protective system (sloping, benching, shoring, or a trench box) is required at 5 ft deep, and shallower if the competent person finds a hazard.","A competent person must inspect the excavation daily, before entry, and after rain, vibration, or any change.","Keep spoil piles, equipment, and materials at least 2 ft back from the edge.","Provide safe egress (ladder, ramp, stairs) within 25 ft of workers in trenches 4 ft or deeper.","Test the atmosphere in excavations deeper than 4 ft where a hazardous atmosphere may exist."]},{"h": "SAFE WORK PRACTICES","body": ["Never enter a trench 5 ft or deeper without an approved protective system in place.","Confirm the competent person has inspected the excavation for your shift.","Keep the spoil pile and equipment back from the edge and use egress within 25 ft.","Call 811 to locate utilities before digging; support or expose them safely.","Keep water pumped out; never work in a trench with accumulating water without controls.","Know the soil type (A, B, or C) drives the slope/shoring — when in doubt, treat it as Type C."]},{"h": "PPE NEEDED","body": ["Hard hat, safety glasses, high-visibility apparel, gloves, and safety-toe boots","Protective footwear suited to mud, water, and uneven ground","Fall protection when exposed to open edges or crossings where required","Gas monitor and respiratory protection only when atmospheric testing or plan requires it"]}]},{"id": "30","title": "Confined Space Entry","ref": "Excavation & Confined Spaces   |   OSHA 29 CFR 1926 Subpart AA","sections": [{"h": "SUMMARY","body": ["Confined spaces can kill entrants and rescuers through atmosphere, engulfment, or restricted access hazards. This talk reinforces permits, continuous monitoring, ventilation, attendants, communication, retrieval systems, and never attempting an unprotected rescue."]},{"h": "IMPORTANT FACTS","body": ["Confined spaces cause roughly 90 to 120 deaths per year, many involving would-be rescuers. Safe oxygen range is 19.5% to 23.5%, and atmospheric hazards are a leading cause of confined-space fatalities."]},{"h": "WHY IT MATTERS","body": ["Confined spaces — tanks, vaults, manholes, pits, and silos — can hold atmospheres that kill instantly. Around 90 to 120 workers die in confined spaces each year, and the most chilling statistic is that roughly 60% of the victims are would-be rescuers who rushed in to help. That's why testing, permits, and a trained attendant are non-negotiable."]},{"h": "KEY HAZARDS","body": ["Oxygen-deficient (<19.5%) or oxygen-enriched (>23.5%) atmospheres","Toxic and flammable gases and vapors","Engulfment by liquids or free-flowing solids","Limited entry/exit and would-be-rescuer fatalities"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Permit-required confined spaces must be identified, labeled, and never entered without an authorized permit.","Test the atmosphere before and continuously during entry: oxygen 19.5–23.5%, flammables below 10% of the LEL, toxics below their limits.","An attendant must remain outside and in constant contact with entrants for the entire entry.","Non-entry rescue equipment and a rescue plan must be in place before entry — no unprotected rescues."]},{"h": "SAFE WORK PRACTICES","body": ["Identify permit spaces and never enter without an authorized, signed permit.","Test the atmosphere first and keep monitoring continuously during the work.","Ventilate the space and control any connected energy or lines (lockout).","Keep a trained attendant outside maintaining constant contact.","Use required PPE and retrieval lines; know the rescue plan before entry.","If an alarm sounds or conditions change, evacuate immediately — never rush in to rescue."]},{"h": "PPE NEEDED","body": ["Calibrated atmospheric monitor for oxygen, LEL, and toxic gases","Harness, retrieval line, tripod/davit, and non-entry rescue equipment when required","Respirator or supplied-air/SCBA only as specified by the permit and hazard assessment","Hard hat, gloves, eye protection, boots, and communication equipment"]}]},{"id": "31","title": "Fire Prevention & Protection","ref": "Fire, Hot Work & Flammables   |   OSHA 29 CFR 1926 Subpart F","sections": [{"h": "SUMMARY","body": ["Construction sites combine ignition sources, fuels, and combustible debris in one place. This talk covers housekeeping, proper flammable storage, extinguisher placement and the P.A.S.S. method, keeping exits and equipment access clear, and knowing the site alarm and evacuation route."]},{"h": "IMPORTANT FACTS","body": ["Extinguishers must be accessible within required travel distances, P.A.S.S. means Pull, Aim, Squeeze, Sweep, and combustible debris combined with an ignition source can create a fast-spreading fire."]},{"h": "WHY IT MATTERS","body": ["Construction sites are full of ignition sources, fuels, and combustible debris. A small fire can grow and cut off exits in minutes, especially in a partially built structure. Prevention, good housekeeping, clear exits, and knowing how to use an extinguisher protect both lives and the project."]},{"h": "KEY HAZARDS","body": ["Combustible debris and flammable-liquid storage","Hot work performed near combustibles","Blocked exits and obstructed extinguisher access","Faulty temporary heating and electrical equipment"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["A fire extinguisher rated at least 2A must be within 100 ft of travel of most work areas (75 ft for concentrated Class A hazards).","Extinguishers must be inspected and maintained, with access kept clear.","Combustible debris must be removed regularly and flammables stored in approved containers.","Exits, exit routes, and firefighting equipment must be kept clear and marked."]},{"h": "SAFE WORK PRACTICES","body": ["Keep combustible debris cleaned up and disposed of regularly.","Store flammable liquids in approved, labeled containers away from ignition sources.","Know extinguisher locations and use P.A.S.S.: Pull the pin, Aim at the base, Squeeze, Sweep.","Keep exits and extinguisher access clear at all times.","Maintain temporary heaters with proper clearances and ventilation.","Know the site alarm, evacuation route, and muster point; report damaged extinguishers."]},{"h": "PPE NEEDED","body": ["Hard hat, safety glasses, gloves, high-visibility apparel, and safety-toe boots","Fire-resistant gloves or clothing when assigned to fire watch or hot work support","Respiratory protection only when smoke, fumes, or exposure assessment requires it","Correct fire extinguisher nearby and accessible"]}]},{"id": "32","title": "Hot Work — Welding, Cutting & Brazing","ref": "Fire, Hot Work & Flammables   |   OSHA 29 CFR 1926 Subpart J","sections": [{"h": "SUMMARY","body": ["Welding and cutting throw sparks and slag that travel far and smolder long after the work stops. This talk covers the hot-work permit, clearing or shielding combustibles within 35 feet, posting a fire watch during and after the job, ventilating fumes, and using the correct shade lens and PPE."]},{"h": "IMPORTANT FACTS","body": ["Hot work requires clearing or shielding combustibles within 35 feet, maintaining a fire watch during and after work, and recognizing that sparks can travel more than 35 feet and smolder after the task is complete."]},{"h": "WHY IT MATTERS","body": ["Welding and cutting produce sparks, molten slag, intense heat, toxic fumes, and UV/IR radiation. Sparks can travel more than 35 feet and settle into cracks where they smolder — many hot-work fires ignite well after the work is finished. A permit, a cleared area, and a fire watch are what prevent those delayed disasters."]},{"h": "KEY HAZARDS","body": ["Fire and explosion from sparks and slag","Toxic fumes and gases (including in coated or galvanized metal)","UV/IR radiation burns to eyes and skin (\"arc flash\"/\"welder's flash\")","Compressed-gas, electric-shock, and confined-space hazards"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["A hot-work permit is required; combustibles within 35 ft must be removed or shielded with fire-resistant covers.","A trained fire watch must be posted during the work and for at least 30 minutes afterward (NFPA 51B recommends up to 60).","A fire extinguisher must be immediately available at the work location.","Provide ventilation or local exhaust for fumes; use respiratory protection where required."]},{"h": "SAFE WORK PRACTICES","body": ["Complete the hot-work permit and clear or shield all combustibles within 35 ft.","Post a fire watch during the work and for at least 30 minutes after.","Keep a fire extinguisher within reach at the work location.","Ventilate for fumes or use local exhaust; wear a respirator when required.","Use the correct shade lens and full PPE — jacket, gloves, and face/eye protection.","Screen the area to protect others; inspect hoses, cables, and regulators, and secure/cap cylinders."]},{"h": "PPE NEEDED","body": ["Welding helmet or face shield with correct shade lens and safety glasses underneath","Flame-resistant jacket, welding gloves, sleeves, apron, and safety-toe boots","Hearing protection for cutting, grinding, or noisy hot work","Respiratory protection when ventilation or exposure assessment requires it"]}]},{"id": "33","title": "Flammable & Combustible Liquids","ref": "Fire, Hot Work & Flammables   |   OSHA 29 CFR 1926.152","sections": [{"h": "SUMMARY","body": ["It is the vapor, not the liquid, that ignites. This talk covers approved safety cans, bonding and grounding during transfer to prevent static sparks, keeping flammables away from ignition sources and hot work, safe refueling, ventilation, and spill readiness."]},{"h": "IMPORTANT FACTS","body": ["Flammable vapors ignite more readily than the liquid itself, bonding and grounding help prevent static-spark ignition, and approved safety cans include self-closing lids and flame arrestors."]},{"h": "WHY IT MATTERS","body": ["Fuels, solvents, and adhesives give off vapors that ignite easily, and it's those vapors — not the liquid itself — that catch fire and explode. Improper storage and handling of flammable liquids is a leading cause of jobsite fires. A tiny static spark during transfer is enough to set off accumulated vapor."]},{"h": "KEY HAZARDS","body": ["Vapor buildup igniting from sparks, heat, or flame","Improper or unlabeled storage containers","Static discharge during transfer and fueling","Spills and inadequate ventilation"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Flammable liquids must be stored and dispensed from approved, labeled safety cans (self-closing lid, flame arrestor).","Containers and receiving vessels must be bonded and grounded during transfer.","Limit quantities at the work area and store bulk flammables in approved cabinets/rooms.","Keep flammables away from ignition sources, exits, and hot work."]},{"h": "SAFE WORK PRACTICES","body": ["Store flammable liquids in approved, labeled safety cans with self-closing lids.","Bond and ground containers when transferring to prevent static sparks.","Keep flammables away from ignition sources, heat, and hot work.","Shut off engines before refueling and avoid spills.","Ventilate work areas where vapors can accumulate.","Keep spill cleanup materials and the correct extinguisher nearby."]},{"h": "PPE NEEDED","body": ["Chemical-resistant gloves selected from the SDS","Safety glasses or splash goggles; face shield for transfer or splash risk","Flame-resistant clothing where ignition exposure is possible","Respirator only when ventilation/exposure assessment and program require it"]}]},{"id": "34","title": "PPE — Head, Eye & Face Protection","ref": "PPE & Personal Safety   |   OSHA 29 CFR 1926.95–.102","sections": [{"h": "SUMMARY","body": ["Head, eye, and face protection prevent serious injuries from falling objects, flying particles, chemical splash, and optical radiation. This talk reinforces hazard-matched PPE, daily inspection, proper ANSI-rated protection, and replacing damaged equipment."]},{"h": "IMPORTANT FACTS","body": ["About 2,000 workplace eye injuries occur every day in the U.S., roughly 90% of eye injuries are preventable with proper protection, hard hats should meet ANSI Z89.1, and safety glasses should meet ANSI Z87.1."]},{"h": "WHY IT MATTERS","body": ["PPE is your last line of defense when other controls can't remove a hazard. About 2,000 U.S. workers suffer an eye injury on the job every day — and roughly 90% of those injuries could be prevented or reduced with proper eye protection. A hard hat and Z87 glasses prevent the vast majority of head and eye injuries in construction."]},{"h": "KEY HAZARDS","body": ["Falling and flying objects striking the head","Flying particles, dust, and chemical splash to the eyes","Impact and penetration to the face","Damaged, expired, or modified PPE"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Head protection meeting ANSI Z89.1 is required wherever there is a risk of impact or falling-object head injury.","Eye and face protection meeting ANSI Z87.1 is required for operations with flying particles, chemicals, or radiation.","Employers must assess hazards and select appropriate PPE; damaged PPE must be replaced.","Face shields are supplemental — wear primary eye protection (glasses/goggles) underneath."]},{"h": "SAFE WORK PRACTICES","body": ["Wear an approved hard hat in all designated areas; replace it after any impact and per the manufacturer's service life.","Wear Z87-rated safety glasses with side shields at all times on site.","Add a face shield and goggles for grinding, cutting, chipping, and chemical work.","Match the eye protection to the hazard — impact, dust, splash, or optical radiation.","Inspect PPE before use; remove cracked, faded, or damaged gear from service.","Don't drill, paint over cracks, or otherwise modify hard hats — it weakens them."]},{"h": "PPE NEEDED","body": ["ANSI Z89.1 hard hat appropriate for impact and electrical exposure","ANSI Z87.1 safety glasses with side shields as minimum eye protection","Goggles and face shield for splash, dust, grinding, or cutting tasks","Special shade lenses for welding, cutting, brazing, or optical radiation exposure"]}]},{"id": "35","title": "Hand Protection & Preventing Lacerations","ref": "PPE & Personal Safety   |   OSHA 29 CFR 1926.95 / General Duty","sections": [{"h": "SUMMARY","body": ["Hand protection prevents cuts, punctures, crush injuries, burns, and chemical exposure. This talk reinforces selecting the right glove, keeping hands out of line-of-fire and pinch points, using tools instead of fingers, and avoiding gloves near rotating equipment."]},{"h": "IMPORTANT FACTS","body": ["Hands and fingers account for about 23% of workplace injuries, lacerations make up a large share of hand injuries, many hand injuries occur when gloves are not worn, and hand injuries send many workers to emergency care each year."]},{"h": "WHY IT MATTERS","body": ["Hand and finger injuries make up about 23% of all workplace injuries — the most frequent preventable injury there is — and send roughly a million workers to the ER each year. Lacerations are the largest share at about 63%. The pattern is clear: most hand injuries happen to workers who weren't wearing gloves or had their hands in the line of fire."]},{"h": "KEY HAZARDS","body": ["Cuts and lacerations from blades and sharp edges","Pinch points and crush injuries","Punctures from nails, wire, and rebar","Chemical, abrasion, and thermal injuries"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Employers must assess hazards and provide appropriate hand protection (cut, chemical, impact, or thermal).","Cut-resistant gloves are rated by ANSI cut level (A1–A9) — match the level to the task.","Gloves must not be worn near rotating machinery that could catch and pull them in.","Damaged gloves must be replaced."]},{"h": "SAFE WORK PRACTICES","body": ["Select the right glove for the task — cut-resistant, chemical, impact, or heat.","Keep hands out of pinch points and the line of fire; guide material with tools, not fingers.","Use sharp blades, cut away from your body, and retract utility knives after each cut.","Cap exposed rebar and remove or bend over protruding nails.","Inspect gloves for wear and replace when damaged — but never wear them near rotating equipment.","Report near-misses so the hazard gets fixed before someone is cut."]},{"h": "PPE NEEDED","body": ["Cut-resistant gloves matched to ANSI cut level for the task","Impact gloves for pinch, crush, or material-handling exposure","Chemical-resistant or thermal gloves where SDS or heat exposure requires it","Do not wear gloves around rotating machinery that could pull them in"]}]},{"id": "36","title": "Foot Protection","ref": "PPE & Personal Safety   |   OSHA 29 CFR 1926.96","sections": [{"h": "SUMMARY","body": ["Foot protection reduces crush, puncture, slip, electrical, and chemical injuries. This talk reinforces choosing job-appropriate safety footwear, inspecting boots, using puncture-resistant or EH-rated footwear when needed, and maintaining good footing."]},{"h": "IMPORTANT FACTS","body": ["Safety footwear should meet ASTM F2413 for the site hazard, feet face crush, puncture, slip, electrical, and chemical hazards throughout the workday, and puncture-resistant soles help stop nails and sharp debris."]},{"h": "WHY IT MATTERS","body": ["Feet are exposed to dropped materials, punctures, and slips throughout the workday. Proper safety footwear prevents crushed toes, puncture wounds through the sole, and many slip-and-fall injuries. The right boot for the site's hazards is inexpensive protection against injuries that can put a worker off their feet for months."]},{"h": "KEY HAZARDS","body": ["Dropped tools and materials crushing toes","Punctures from nails and sharp debris underfoot","Slips on wet, muddy, oily, or uneven surfaces","Electrical and chemical hazards to the feet"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Protective footwear must meet ASTM F2413 (or the applicable standard) for the site's hazards.","Employers must assess foot hazards and require appropriate footwear.","Use puncture-resistant soles where nails/sharp debris are present, and EH-rated footwear near electrical hazards.","Damaged footwear (worn soles, exposed toe caps) must be replaced."]},{"h": "SAFE WORK PRACTICES","body": ["Wear safety-toe boots rated for the jobsite in all designated areas.","Use puncture-resistant soles where nails and sharp debris are present.","Choose slip-resistant outsoles for wet or slick conditions.","Wear EH-rated footwear near electrical work.","Keep laces tied and boots in good repair — replace worn soles.","Watch footing on uneven ground, ramps, and cluttered walkways; keep walkways clear."]},{"h": "PPE NEEDED","body": ["ASTM-rated safety-toe footwear for crush and impact exposure","Puncture-resistant soles where nails, scrap, or sharp debris are present","Slip-resistant outsoles for mud, water, oil, ice, or dock work","EH-rated footwear where electrical hazards exist"]}]},{"id": "37","title": "High-Visibility Apparel & Work Zone Safety","ref": "PPE & Personal Safety   |   OSHA 29 CFR 1926 Subpart G / MUTCD","sections": [{"h": "SUMMARY","body": ["High-visibility apparel and work-zone controls help workers on foot stay visible and separated from traffic and equipment. This talk reinforces correct apparel class, traffic-control setup, blind-spot awareness, buffer zones, lighting, and operator communication."]},{"h": "IMPORTANT FACTS","body": ["Work-zone vehicle strikes kill workers every year, runovers and backovers are a major share of road-worker deaths, and high-visibility apparel should meet ANSI/ISEA 107 Class 2 or Class 3 based on exposure."]},{"h": "WHY IT MATTERS","body": ["Workers on foot near traffic and mobile equipment are at high risk of being struck. An average of 54 workers are killed by vehicles in work zones each year, and runovers/backovers — mostly by dump trucks — cause nearly half of road-worker deaths. High-visibility apparel and a properly set-up work zone are what make you seen before it's too late."]},{"h": "KEY HAZARDS","body": ["Struck-by passing traffic and mobile equipment","Poor visibility at night, dawn, dusk, and in bad weather","Blind spots of trucks and heavy equipment","Improperly set up or degraded traffic control"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Workers exposed to traffic or equipment must wear ANSI/ISEA 107 Class 2 or Class 3 high-visibility apparel (Class 3 for higher speeds/night).","Temporary traffic control must follow the approved plan and the MUTCD.","Provide a buffer space between workers and live traffic, and a flagger where required.","Backing equipment requires a spotter and/or an operable backup alarm."]},{"h": "SAFE WORK PRACTICES","body": ["Wear the correct class of high-visibility apparel for your exposure and the time of day.","Set up traffic control (cones, signs, barriers) per the plan and keep it maintained.","Keep a buffer between workers and live traffic; never turn your back to traffic.","Make eye contact with drivers and operators before entering their path.","Stay out of equipment blind spots and swing/backing zones.","Add lighting and reflective materials for night work; follow the flagger's signals."]},{"h": "PPE NEEDED","body": ["ANSI/ISEA 107 Class 2 or Class 3 high-visibility apparel based on traffic speed and exposure","Hard hat, safety glasses, and safety-toe boots","Night-work reflective gear, lighting, or illuminated wands where assigned","Hearing protection where traffic or equipment noise requires it"]}]},{"id": "38","title": "Housekeeping & Slips, Trips, Falls","ref": "Site Operations & Warehouse   |   OSHA 29 CFR 1926.25 / 1910.22","sections": [{"h": "SUMMARY","body": ["Housekeeping controls prevent slips, trips, falls, punctures, and blocked-access hazards. This talk reinforces cleaning as work progresses, routing cords and hoses safely, removing protruding nails, managing spills, maintaining lighting, and keeping exits clear."]},{"h": "IMPORTANT FACTS","body": ["Slips, trips, and falls are among the most common injury sources, same-level falls drive many lost workdays, and many of these incidents trace back to housekeeping, clutter, cords, spills, and uneven walking surfaces."]},{"h": "WHY IT MATTERS","body": ["Slips, trips, and falls on the same level are one of the most common sources of workplace injury — and nearly all of them trace directly back to housekeeping. Clutter, cords, spills, and protruding nails cause sprains, fractures, and worse. A clean, organized site is measurably safer and more productive."]},{"h": "KEY HAZARDS","body": ["Clutter, scrap, debris, and trailing cords and hoses","Wet, muddy, oily, or icy walking surfaces","Protruding nails and materials in walkways","Poor lighting and unmarked changes in elevation"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Combustible scrap and debris must be removed regularly; containers provided for waste.","Form and scrap lumber with protruding nails must be removed from work areas, passageways, and stairs.","Walking and working surfaces must be kept clean, orderly, and in a sanitary condition.","Aisles, passageways, and exits must be kept clear."]},{"h": "SAFE WORK PRACTICES","body": ["Clean up debris and scrap as you work — don't leave it for later or the next crew.","Keep walkways, stairs, and exits clear of tools, cords, and materials.","Route cords and hoses overhead or along edges, not across walkways.","Clean up spills immediately and mark wet or slippery areas.","Remove or bend over protruding nails and stack materials neatly and stably.","Keep work areas well lit and mark trip hazards and elevation changes."]},{"h": "PPE NEEDED","body": ["Slip-resistant safety-toe footwear suited to site conditions","Work gloves for debris, scrap, nails, and material handling","Safety glasses and hard hat in active construction areas","High-visibility apparel where equipment, vehicles, or traffic are present"]}]},{"id": "39","title": "Manual Material Handling & Ergonomics","ref": "Site Operations & Warehouse   |   OSHA OSH Act General Duty Clause","sections": [{"h": "SUMMARY","body": ["Manual material handling and ergonomics reduce strains, sprains, and long-term musculoskeletal injuries. This talk reinforces planning the lift, using mechanical aids, team lifting, avoiding twisting, storing materials at safe heights, and reporting early discomfort."]},{"h": "IMPORTANT FACTS","body": ["Overexertion is a leading cause of lost-time injury, musculoskeletal disorders drive a large share of injury costs, and many lifting-related back injuries are preventable with planning, equipment, and teamwork."]},{"h": "WHY IT MATTERS","body": ["Overexertion and repetitive strain are among the leading causes of lost-time injuries and account for a large share of workers'-comp costs. Sprains, strains, and back injuries from lifting are largely preventable with good technique, teamwork, and the right equipment. These injuries build up over time and can end careers."]},{"h": "KEY HAZARDS","body": ["Back and shoulder strain from heavy or awkward lifts","Repetitive motion and sustained awkward postures","Twisting while carrying a load","Overhead and below-knee lifting"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Under the General Duty Clause, employers must address recognized ergonomic hazards that cause injury.","Provide mechanical aids (carts, dollies, hoists) and team-lift procedures for heavy/bulky loads.","Design tasks to keep frequent materials between knee and shoulder height where feasible.","Train workers on safe lifting technique and encourage early reporting of strains."]},{"h": "SAFE WORK PRACTICES","body": ["Size up the load; get help or use equipment for heavy or bulky items.","Lift with your legs, keep the load close, and keep your back straight.","Don't twist while lifting — turn with your feet.","Break large loads into smaller ones when possible.","Store frequently used materials between knee and shoulder height.","Take micro-breaks, rotate repetitive tasks, and ask for a team lift when in doubt."]},{"h": "PPE NEEDED","body": ["Grip gloves for handling materials without losing control","Safety-toe footwear with slip-resistant soles","Back support only if required by company policy; do not rely on it as a substitute for safe lifting","Mechanical aids, carts, dollies, hoists, or team-lift assistance as the primary control"]}]},{"id": "40","title": "Warehouse & Loading Dock Safety","ref": "Site Operations & Warehouse   |   OSHA 29 CFR 1910.176 / 1910.178","sections": [{"h": "SUMMARY","body": ["Warehouse and dock work keeps forklifts, pedestrians, racking, and trailers in constant motion together. This talk covers separating pedestrian and forklift traffic, chocking and restraining trailers before entry, keeping dock edges clear, respecting rack capacities, and maintaining visibility at blind corners."]},{"h": "IMPORTANT FACTS","body": ["Forklifts cause roughly 85 deaths and more than 34,000 serious injuries in U.S. workplaces every year, and forklift/pedestrian collisions are among the top warehouse hazards. Trailer creep and unsecured trailers are a leading cause of dock incidents, and overloaded or damaged racking causes collapses and falling-product injuries."]},{"h": "WHY IT MATTERS","body": ["Warehouse and 3PL operations combine forklifts, storage racks, and loading docks — a mix that leads to struck-by injuries, falls from docks, and rack collapses. Well-organized traffic flow, secured trailers, and rated racking keep people safe amid constant movement of heavy loads."]},{"h": "KEY HAZARDS","body": ["Forklift/pedestrian collisions in aisles and at intersections","Falls from loading docks and gaps between the dock and trailer","Overloaded or damaged storage racks and falling product","Trailer creep and unsecured trailers during loading"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Aisles and passageways must be kept clear, in good repair, and marked where mechanical handling equipment is used.","Storage must be stable and secure against sliding or collapse; observe rack rated capacities.","Dock and trailer procedures must prevent movement — wheel chocks and/or dock locks/restraints.","Powered-industrial-truck rules (1910.178) apply to all forklift operations (see PIT talk)."]},{"h": "SAFE WORK PRACTICES","body": ["Separate pedestrian and forklift traffic; use marked walkways and crossings.","Chock trailer wheels and engage dock locks/restraints before loading or unloading.","Keep dock edges and open door areas clear; use barriers when doors are open.","Keep racks within rated capacity, load stable, and report damaged uprights immediately.","Maintain visibility at blind corners with mirrors and horns.","Confirm the trailer is secured and watch for trailer creep before entering."]},{"h": "PPE NEEDED","body": ["High-visibility apparel for dock, aisle, and forklift-traffic areas","Safety-toe footwear with slip-resistant soles","Hard hat where overhead storage or falling-product hazards exist","Gloves for pallets, banding, shrink wrap, and material handling"]}]},{"id": "41","title": "Concrete & Masonry Construction","ref": "Site Operations & Warehouse   |   OSHA 29 CFR 1926 Subpart Q","sections": [{"h": "SUMMARY","body": ["Concrete and masonry work brings collapse, impalement, caustic burns, and silica dust. This talk covers not loading formwork or stripping shoring until strength is reached, capping exposed rebar, bracing walls and enforcing limited-access zones, protecting skin from wet concrete, and controlling silica dust."]},{"h": "IMPORTANT FACTS","body": ["Wet concrete is caustic: prolonged skin contact causes chemical burns severe enough to require skin grafts, often with little immediate pain to warn the worker. Formwork and shoring collapse from premature loading is a leading concrete hazard, and falls onto unprotected projecting rebar cause fatal impalements — which is why rebar caps and guarding are required."]},{"h": "WHY IT MATTERS","body": ["Concrete and masonry work brings formwork and shoring collapse, rebar impalement, caustic burns from wet concrete, and silica dust. Structures under construction must be shored, braced, and cured to strength before they can carry loads — and a fall onto exposed rebar can be fatal, which is why impalement protection is required."]},{"h": "KEY HAZARDS","body": ["Formwork and shoring collapse from premature loading","Rebar impalement from falls onto exposed bar","Chemical (caustic) burns from wet concrete","Silica dust from cutting and grinding masonry"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Formwork and shoring must be designed, inspected, and not loaded until the concrete reaches required strength per the plan.","Protruding reinforcing steel onto which workers could fall must be guarded to prevent impalement (caps/covers or guarding).","A limited-access zone must be established next to masonry walls under construction and until braced.","Silica controls apply to cutting/grinding masonry (see the silica talk)."]},{"h": "SAFE WORK PRACTICES","body": ["Don't load formwork or strip shoring until the concrete has reached required strength.","Cap or cover all exposed rebar to protect against impalement.","Brace masonry walls under construction until they are permanently supported.","Wear waterproof gloves and boots; rinse wet-concrete skin contact immediately.","Control silica dust with water or vacuum when cutting or grinding.","Keep clear of concrete pump lines and be alert to hose whip."]},{"h": "PPE NEEDED","body": ["Waterproof gloves, long sleeves, and boots for wet concrete contact","Safety glasses or goggles; face shield for splash or chipping work","Respirator and silica controls when cutting, grinding, or drilling masonry","Hard hat, high-visibility apparel, and safety-toe boots"]}]},{"id": "42","title": "Mobile Equipment & Backover Prevention","ref": "Site Operations & Warehouse   |   OSHA 29 CFR 1926.601 / 1926.602","sections": [{"h": "SUMMARY","body": ["Most workers struck by heavy equipment are hit while it is backing up. This talk covers using spotters and agreed hand signals, verifying backup alarms and lights, staying out of blind zones and travel paths, making eye contact before approaching, and enforcing equipment exclusion zones."]},{"h": "IMPORTANT FACTS","body": ["Runovers and backovers cause about 48% of worker deaths at road construction sites, and an average of 54 workers are killed by vehicles in work zones each year. Dump trucks are the most commonly involved vehicle. Equipment blind zones extend far beyond what most operators expect, which is why a spotter, a working backup alarm, and high-visibility apparel are required."]},{"h": "WHY IT MATTERS","body": ["Workers on foot are struck and run over by trucks and heavy equipment, most often when equipment is backing up. Runovers and backovers cause nearly half of road-construction worker deaths. Equipment blind spots are large — a spotter, a backup alarm, and high-visibility apparel are what close that gap."]},{"h": "KEY HAZARDS","body": ["Backover incidents in equipment blind zones","Workers on foot near operating equipment","Dump trucks, loaders, and rollers reversing","Poor communication between operators and the ground crew"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Vehicles with an obstructed rear view must have a reverse signal alarm audible above surrounding noise, or use a spotter.","Equipment must be inspected before use; defective brakes, lights, or alarms take it out of service.","Establish and enforce internal traffic control plans that separate equipment and workers on foot.","Seat belts must be worn in equipment equipped with rollover protection (ROPS)."]},{"h": "SAFE WORK PRACTICES","body": ["Use a spotter when backing where visibility is limited; agree on hand signals first.","Verify backup alarms and lights work; tag out equipment with defects.","Wear high-visibility apparel and stay out of blind spots and travel paths.","Make eye contact with operators before approaching — never assume they see you.","Establish and respect equipment exclusion zones.","Operators: walk around and check behind before moving, and use mirrors and cameras."]},{"h": "PPE NEEDED","body": ["High-visibility apparel for ground workers, spotters, and operators outside equipment","Hard hat, safety glasses, gloves, and safety-toe boots","Seat belt when operating equipment with ROPS","Hearing protection where equipment noise requires it"]}]},{"id": "43","title": "Emergency Action Plans & Evacuation","ref": "Safety Programs & Administration   |   OSHA 29 CFR 1926.35 / 1910.38","sections": [{"h": "SUMMARY","body": ["Emergencies are survivable when everyone already knows the plan. This talk covers alarm signals, evacuation routes, muster points and head counts, who is trained in first aid and CPR, where the kit and AED are located, and never re-entering until the all-clear is given."]},{"h": "IMPORTANT FACTS","body": ["In an emergency, seconds decide outcomes. OSHA requires a written Emergency Action Plan wherever another standard mandates one, covering alarms, evacuation routes, emergency procedures, and a post-evacuation head count. Crews who know the alarm signal, the exit route, and the muster point before an event evacuate faster and are accounted for sooner."]},{"h": "WHY IT MATTERS","body": ["When an emergency hits — fire, explosion, medical crisis, severe weather, or a chemical release — seconds count and confusion kills. Knowing the plan before it happens is the difference between an orderly evacuation and chaos. Everyone should know the alarm, the routes, the muster point, and who does what."]},{"h": "KEY HAZARDS","body": ["Fire, explosion, and chemical release","Medical emergencies and serious injuries","Severe weather and structural collapse","Confusion from not knowing routes, roles, and signals"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["A written Emergency Action Plan is required where other OSHA standards mandate one; it covers reporting, evacuation routes, and procedures.","Alarm systems must be recognizable and used to alert workers.","Procedures must account for workers who remain to operate critical functions and for head counts after evacuation.","Workers must be trained on the plan and their roles."]},{"h": "SAFE WORK PRACTICES","body": ["Know the site's emergency procedures, alarm signals, and evacuation routes.","Know the muster (assembly) point and report there for the head count.","Know who is trained in first aid/CPR and where the first-aid kit and AED are.","Keep exit routes and muster points clear and unobstructed.","When calling 911, clearly state the location and nature of the emergency.","Don't re-enter until the all-clear is given; follow the incident commander's directions."]},{"h": "PPE NEEDED","body": ["Site-required hard hat, safety glasses, high-visibility apparel, gloves, and safety-toe boots","Emergency role-specific PPE such as vest, radio, flashlight, or first-aid gloves","Weather-specific gear for evacuation during heat, cold, rain, or low visibility","Respiratory, chemical, or fire-response PPE only for trained and assigned responders"]}]},{"id": "44","title": "First Aid & Medical Services","ref": "Safety Programs & Administration   |   OSHA 29 CFR 1926.50","sections": [{"h": "SUMMARY","body": ["Fast, correct first aid bridges the gap until EMS arrives. This talk covers where the first-aid kit, eyewash, and AED are located, who is trained and certified, controlling serious bleeding, flushing chemical eye contact for a full 15 minutes, and reporting every injury."]},{"h": "IMPORTANT FACTS","body": ["When no infirmary, clinic, or hospital is in near proximity, OSHA requires a person trained in first aid to be on site. In cardiac arrest, brain damage can begin within about four minutes, and survival odds fall sharply for every minute without CPR or defibrillation. Chemical eye contact requires at least 15 minutes of continuous eyewash flushing."]},{"h": "WHY IT MATTERS","body": ["When professional medical help isn't in near proximity, trained first-aiders and ready supplies are what bridge the gap until EMS arrives. Fast, correct first aid can stop serious bleeding, keep an airway open, and prevent shock. In a cardiac emergency, brain damage can begin within about four minutes — response time is everything."]},{"h": "KEY HAZARDS","body": ["Serious bleeding, fractures, and burns","Delayed care when EMS is far away","Contaminated first-aid supplies or missing items","Untrained response that worsens an injury"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["When no infirmary/clinic/hospital is in near proximity, a person trained in first aid must be available on site.","First-aid supplies must be readily available and appropriate for the hazards.","Where corrosives are used, suitable eyewash/quick-drench facilities must be provided for immediate use.","Emergency phone numbers and the means to summon help must be posted/available."]},{"h": "SAFE WORK PRACTICES","body": ["Know where first-aid kits, eyewash stations, and the AED are located.","Know who is trained and certified in first aid and CPR on your crew.","Provide first aid within your training; don't move seriously injured workers unnecessarily.","Control serious bleeding with direct pressure and summon EMS fast.","Flush chemical eye contact with eyewash for at least 15 minutes.","Keep supplies stocked, sealed, and protected; report all injuries so they're treated and tracked."]},{"h": "PPE NEEDED","body": ["Disposable medical gloves for first aid, bleeding control, or cleanup","Safety glasses, goggles, or face shield for splash potential","CPR shield or barrier device for rescue breathing","Biohazard bags, sharps container, hand sanitizer, and eyewash access where needed"]}]},{"id": "45","title": "Injury Reporting & Recordkeeping","ref": "Safety Programs & Administration   |   OSHA 29 CFR 1904","sections": [{"h": "SUMMARY","body": ["Reporting is how hazards get fixed before they hurt someone worse. This talk covers reporting all injuries and near-misses, OSHA's 8-hour fatality and 24-hour hospitalization/amputation/eye-loss deadlines, the OSHA 300 log, cooperating with investigations, and the ban on retaliation."]},{"h": "IMPORTANT FACTS","body": ["OSHA requires employers to report a work-related fatality within 8 hours, and any inpatient hospitalization, amputation, or loss of an eye within 24 hours. Covered employers must record injuries on the OSHA 300 log and post the 300A summary from February 1 through April 30. Retaliation against a worker for reporting an injury or hazard is illegal."]},{"h": "WHY IT MATTERS","body": ["Reporting every injury and near-miss isn't about blame — it's how hazards get fixed before they hurt someone worse. OSHA also sets hard deadlines for reporting severe incidents, and retaliation for reporting is illegal. A reported near-miss is a free lesson; an unreported one is next month's serious injury."]},{"h": "KEY HAZARDS","body": ["Unreported hazards that injure the next worker","Untreated minor injuries that worsen","Missed severe-incident reporting deadlines","Fear of reporting that hides real risks"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Report any work-related fatality to OSHA within 8 hours.","Report any inpatient hospitalization, amputation, or loss of an eye within 24 hours.","Covered employers must record recordable injuries/illnesses on the OSHA 300 log (301 incident reports; 300A posted Feb–Apr).","Retaliation against workers for reporting injuries or hazards is prohibited."]},{"h": "SAFE WORK PRACTICES","body": ["Report all injuries and illnesses to your supervisor, no matter how minor.","Report near-misses — they reveal hazards before an injury happens.","Get first aid or medical treatment promptly for any injury.","Cooperate with incident investigations to find the root cause, not a scapegoat.","Know the 8-hour and 24-hour OSHA reporting triggers.","Help fix the hazard once it's identified — reporting without action changes nothing."]},{"h": "PPE NEEDED","body": ["No special PPE for reporting itself beyond site-required PPE","First-aid gloves, eye protection, or cleanup PPE when assisting with an incident scene","High-visibility apparel if securing an area near traffic or equipment","Do not enter an unsafe scene without proper training, controls, and PPE"]}]},{"id": "46","title": "Pre-Task Planning & Job Hazard Analysis","ref": "Safety Programs & Administration   |   OSHA Best Practice / General Duty Clause","sections": [{"h": "SUMMARY","body": ["Pre-task planning and job hazard analysis help crews identify hazards before work begins. This talk reinforces breaking the job into steps, assigning controls, involving the full crew, reassessing when conditions change, and honoring Stop Work Authority."]},{"h": "IMPORTANT FACTS","body": ["Most serious incidents happen on tasks that seemed routine and were never formally planned. A Job Hazard Analysis breaks a task into steps, identifies the hazard in each step, and assigns a control following the hierarchy of controls: elimination, substitution, engineering, administrative, then PPE. Stop Work Authority gives every worker the right to pause a job that is unsafe."]},{"h": "WHY IT MATTERS","body": ["Most incidents happen on tasks that seemed routine and that nobody paused to think through. A quick pre-task plan or Job Hazard Analysis (JHA/JSA) — done together as a crew — catches the hazards before the work starts. It also makes sure everyone knows the plan, their role, and that anyone can stop the job if something isn't right."]},{"h": "KEY HAZARDS","body": ["Rushing into a task without identifying hazards","New or changed conditions not accounted for","Assuming \"we've always done it this way\"","Overlooking who else is affected by the work"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Under the General Duty Clause, employers must identify and control recognized hazards.","A JHA breaks each task into steps, identifies the hazard of each step, and assigns controls.","Controls should follow the hierarchy: elimination, substitution, engineering, administrative, then PPE.","Establish and honor Stop Work Authority for all workers."]},{"h": "SAFE WORK PRACTICES","body": ["Before starting, break the task into steps and identify each step's hazards.","Assign a control to each hazard, working down the hierarchy of controls.","Do the pre-task plan as a crew so everyone knows the risks and their role.","Reassess whenever conditions, crew, or scope change during the shift.","Use Stop Work Authority — anyone can pause work if something is unsafe.","Check for overlapping trades whose work could affect yours, and document the JHA at the work area."]},{"h": "PPE NEEDED","body": ["List task-specific PPE on the JHA before work starts","Baseline site PPE: hard hat, safety glasses, high-visibility apparel, gloves, and safety-toe boots","Add fall, respiratory, hearing, face, chemical, or electrical PPE based on identified hazards","Verify PPE is available, inspected, fitted, and understood by the crew"]}]},{"id": "47","title": "Fit for Duty — Impairment & Fatigue","ref": "Safety Programs & Administration   |   OSHA OSH Act General Duty Clause","sections": [{"h": "SUMMARY","body": ["Fit-for-duty expectations protect the whole crew from impairment, fatigue, distraction, and medication side effects. This talk reinforces reporting rested and sober, checking medication warnings, managing fatigue, speaking up, and avoiding safety-sensitive work when alertness is affected."]},{"h": "IMPORTANT FACTS","body": ["Fatigue can impair performance similarly to alcohol, some prescription and over-the-counter medications can cause dangerous drowsiness, and being fit for duty protects the whole crew."]},{"h": "WHY IT MATTERS","body": ["A worker impaired by alcohol, drugs, certain medications, or severe fatigue is a danger to themselves and everyone around them. Long stretches without sleep can impair reaction time and judgment as much as being over the legal alcohol limit. Being fit for duty means showing up rested, sober, and ready to work safely."]},{"h": "KEY HAZARDS","body": ["Impairment from alcohol, drugs, or medication side effects","Fatigue and drowsiness reducing reaction time and judgment","Distraction from personal stress or devices","Coworkers unsure whether to speak up"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Under the General Duty Clause, employers must keep the workplace free of recognized hazards, including impairment.","Follow the company substance-abuse and fit-for-duty policy.","Safety-sensitive roles may require disclosure of impairing medications to a supervisor.","Manage shift length and rest to control fatigue on high-risk work."]},{"h": "SAFE WORK PRACTICES","body": ["Report to work rested, sober, and free of impairing substances.","Check medication labels for drowsiness warnings and tell your supervisor if your role is safety-sensitive.","Manage fatigue — get adequate rest, especially before high-risk tasks and long shifts.","Stay off your phone during safety-critical work.","Speak up privately to a supervisor if a coworker seems impaired — it may save a life.","Take breaks and hydrate to stay alert.","Do not perform safety-sensitive work if medication, fatigue, or impairment affects alertness"]},{"h": "PPE NEEDED","body": ["No special PPE replaces being rested, sober, and unimpaired","Use normal site-required PPE for the task once fit for duty is confirmed","Cooling, hydration, or cold-weather gear where fatigue is worsened by temperature extremes"]}]},{"id": "48","title": "Driving & Motor Vehicle Safety","ref": "Safety Programs & Administration   |   OSHA OSH Act General Duty Clause","sections": [{"h": "SUMMARY","body": ["Driving and motor vehicle safety requires focused, unimpaired operation every trip. This talk reinforces seat belts, distraction control, speed management, fatigue prevention, vehicle walkarounds, backing with a spotter, and securing tools and loads before travel."]},{"h": "IMPORTANT FACTS","body": ["Motor vehicle crashes are a leading cause of work-related death. Seat belts are the single most effective protection, while distraction, speed, and fatigue drive many serious crashes."]},{"h": "WHY IT MATTERS","body": ["Motor vehicle crashes are one of the leading causes of work-related deaths across all industries. Driving to, from, and around jobsites carries real risk that's easy to underestimate. Seat belts and focused, unimpaired driving are the biggest lifesavers — most work-related vehicle deaths involve an unbelted occupant, distraction, speeding, or fatigue."]},{"h": "KEY HAZARDS","body": ["Distracted driving (phones, navigation, eating)","Speeding and following too closely","Fatigued and drowsy driving","Backing and maneuvering in tight jobsite areas"]},{"h": "OSHA REQUIREMENTS & KEY THRESHOLDS","body": ["Employers must address recognized driving hazards under the General Duty Clause and company fleet policy.","Seat belt use is required for all occupants, every trip.","No texting or hand-held phone use while driving on company business.","Vehicles must be maintained and inspected; loads secured."]},{"h": "SAFE WORK PRACTICES","body": ["Wear your seat belt every trip, every time — the single best protection.","Put the phone down; no calls or texting while driving.","Adjust speed for road, weather, and load, and keep a safe following distance.","Plan the route and don't drive drowsy — pull over and rest if needed.","Do a walkaround and check mirrors before backing; use a spotter in tight areas.","Secure tools and loads so they can't shift, and never drive impaired."]},{"h": "PPE NEEDED","body": ["Seat belt for driver and all passengers, every trip","High-visibility apparel when exiting vehicles in work zones, traffic, or roadside areas","Safety-toe boots, hard hat, gloves, and eye protection when loading, unloading, or entering the jobsite","Weather/emergency kit items such as flashlight, reflective triangles, and first-aid supplies where required"]}]}];
